INSERT INTO kata_kunci (id, kata, materi, jawaban, penjelasan) VALUES
(1, 'Integritas', 'KEPRIBADIAN (Love, Sex, Dating)', 'Keselarasan antara perkataan dan perbuatan. Contoh: Tetap jujur mengembalikan sisa uang belanja walau orang tua tidak mengecek.', 'Integritas adalah fondasi karakter. Remaja dengan integritas tetap melakukan kebenaran baik dilihat maupun tidak. Amsal 11:3 - "Orang yang jujur dipimpin oleh integritasnya"'),
(2, 'Kekudusan', 'KEPRIBADIAN (Love, Sex, Dating)', 'Hidup yang terpisah dari dosa dan dikhususkan bagi Tuhan. Contoh: Menolak ajakan menonton film porno meski teman-teman melakukannya.', '1 Petrus 1:16 - "Kuduslah kamu, sebab Aku kudus". Remaja teladan menjaga pikiran, perkataan, dan perbuatan dari kecemaran'),
(3, 'Pacaran Sehat', 'KEPRIBADIAN (Love, Sex, Dating)', 'Hubungan yang memiliki batasan jelas, melibatkan orang tua, dan fokus pada pengembangan diri. Contoh: Bertemu hanya di tempat umum, tidak berduaan di kamar tertutup.', 'Batasan melindungi dari dosa seksual sebelum waktunya. Remaja teladan memprioritaskan studi dan pelayanan daripada hubungan yang mengikat'),
(4, 'Seks Bebas', 'KEPRIBADIAN (Love, Sex, Dating)', 'Hubungan seksual di luar pernikahan yang dilarang Alkitab. Contoh: Berani menolak ajakan "coba-coba" dari pacar dengan alasan Firman Tuhan.', '1 Korintus 6:18 - "Jauhkanlah diri dari percabulan". Dampaknya: penyakit kelamin, kehamilan tak diinginkan, trauma psikologis'),
(5, 'Pergaulan Sehat', 'KEPRIBADIAN (Love, Sex, Dating)', 'Interaksi sosial yang positif dan membangun karakter. Contoh: Memilih teman yang rajin beribadah dan berprestasi, bukan yang hanya suka bersenang-senang.', 'Amsal 13:20 - "Siapa bergaul dengan orang bijak menjadi bijak". Remaja teladan selektif dalam memilih sahabat'),
(6, 'Kontrol Diri', 'KEPRIBADIAN (Love, Sex, Dating)', 'Kemampuan mengendalikan emosi, keinginan, dan tindakan. Contoh: Tidak langsung marah ketika diprovokasi, tetapi menenangkan diri dan merespon dengan bijak.', 'Galatia 5:23 - "Penguasaan diri" adalah buah Roh. Remaja teladan tidak mudah terprovokasi dan bisa menahan amarah'),
(7, 'Cinta Kasih (Agape)', 'KEPRIBADIAN (Love, Sex, Dating)', 'Kasih tanpa syarat yang berasal dari Allah. Contoh: Tetap mengasihi teman yang menyakiti, mendoakannya, bukan membalas dendam.', '1 Korintus 13:4-7 - Kasih sabar, murah hati, tidak cemburu. Remaja teladan mengasihi seperti Kristus mengasihi gereja'),
(8, 'Kejujuran', 'KEPRIBADIAN (Love, Sex, Dating)', 'Berkata dan bertindak sesuai kebenaran. Contoh: Mengaku kepada guru ketika lupa mengerjakan PR, tidak menyontek saat ujian.', 'Efesus 4:25 - "Buanglah dusta dan katakanlah benar". Remaja teladan lebih baik dapat nilai rendah dengan jujur daripada nilai tinggi dengan curang'),
(9, 'Kerendahan Hati', 'KEPRIBADIAN (Love, Sex, Dating)', 'Tidak sombong dan mengakui keterbatasan diri. Contoh: Mau belajar dari teman yang lebih pintar, tidak gengsi bertanya.', 'Filipi 2:3 - "Dengan rendah hati anggaplah orang lain lebih utama daripadamu". Remaja teladan tidak mencari pujian'),
(10, 'Kesabaran', 'KEPRIBADIAN (Love, Sex, Dating)', 'Kemampuan menunggu dengan tenang tanpa mengeluh. Contoh: Sabar menunggu giliran presentasi, tidak memotong pembicaraan orang lain.', 'Roma 12:12 - "Bersabarlah dalam kesesakan". Remaja teladan percaya waktu Tuhan adalah yang terbaik'),
(11, 'Tanggung Jawab', 'KEPRIBADIAN (Love, Sex, Dating)', 'Kesediaan menanggung konsekuensi dari tindakan sendiri. Contoh: Mengakui kesalahan dan memperbaiki, tidak menyalahkan orang lain.', 'Galatia 6:5 - "Setiap orang akan memikul tanggungannya sendiri". Remaja teladan dewasa dalam bertanggung jawab'),
(12, 'Empati', 'KEPRIBADIAN (Love, Sex, Dating)', 'Kemampuan merasakan apa yang dirasakan orang lain. Contoh: Menghibur teman yang sedang berduka, tidak mengejek kesulitan orang lain.', 'Roma 12:15 - "Bersukacitalah dengan orang yang bersukacita, menangislah dengan orang yang menangis". Remaja teladan peka pada sesama'),
(13, 'Ketekunan', 'KEPRIBADIAN (Love, Sex, Dating)', 'Terus berusaha meski menghadapi kegagalan. Contoh: Tetap belajar meski nilai ulangan jelek, tidak menyerah.', 'Yakobus 1:12 - "Berbahagialah orang yang bertahan dalam pencobaan". Remaja teladan tidak mudah putus asa'),
(14, 'Optimisme', 'KEPRIBADIAN (Love, Sex, Dating)', 'Memandang masa depan dengan harapan positif. Contoh: Yakin bisa memperbaiki nilai meski saat ini rendah, karena Tuhan memberikan kemampuan.', 'Roma 8:28 - "Allah bekerja dalam segala sesuatu untuk mendatangkan kebaikan". Remaja teladan melihat peluang di balik masalah'),
(15, 'Pemaaf', 'KEPRIBADIAN (Love, Sex, Dating)', 'Rela melepaskan hak untuk membalas dendam. Contoh: Memaafkan teman yang menyebarkan gosip, tidak menyimpan dendam.', 'Efesus 4:32 - "Hendaklah kamu saling mengampuni, sama seperti Allah telah mengampuni kamu". Remaja teladan bebas dari kepahitan'),
(16, 'Disiplin', 'KEPRIBADIAN (Love, Sex, Dating)', 'Melakukan hal yang benar secara konsisten. Contoh: Bangun pagi setiap hari untuk berdoa dan baca Alkitab, meski hari libur.', 'Amsal 12:1 - "Siapa mengabaikan didikan menghina dirinya sendiri". Remaja teladan terbiasa dengan rutinitas positif'),
(17, 'Keberanian Moral', 'KEPRIBADIAN (Love, Sex, Dating)', 'Berani melakukan kebenaran walau sendirian. Contoh: Menegur teman yang merokok di lingkungan gereja, berani berkata "tidak" pada ajakan narkoba.', 'Yosua 1:9 - "Kuatkan dan teguhkanlah hatimu". Remaja teladan tidak takut berbeda demi kebenaran'),
(18, 'Rasa Hormat', 'KEPRIBADIAN (Love, Sex, Dating)', 'Menghargai orang lain, terutama yang lebih tua. Contoh: Mencium tangan orang tua dan guru, berbicara dengan sopan.', 'Keluaran 20:12 - "Hormatilah ayahmu dan ibumu". Remaja teladan tahu tata krama dan sopan santun'),
(19, 'Sikap Melayani', 'KEPRIBADIAN (Love, Sex, Dating)', 'Mendahulukan kepentingan orang lain. Contoh: Rela membersihkan ruang ibadah tanpa diminta, membantu teman yang kesulitan pelajaran.', 'Markus 10:45 - "Anak Manusia datang bukan untuk dilayani, melainkan untuk melayani". Remaja teladan memiliki hati seorang hamba'),
(20, 'Sukacita', 'KEPRIBADIAN (Love, Sex, Dating)', 'Kebahagiaan yang tidak tergantung situasi. Contoh: Tetap tersenyum dan bersyukur meski mengalami masalah, karena tahu Tuhan menyertai.', 'Nehemia 8:10 - "Sukacita karena TUHAN adalah kekuatanmu". Remaja teladan sumber sukacitanya adalah Tuhan'),
(21, 'Ketahanan Mental', 'KEPRIBADIAN (Love, Sex, Dating)', 'Kemampuan bangkit dari keterpurukan. Contoh: Tidak terpuruk ketika gagal lomba, segera evaluasi dan berlatih lebih giat.', '2 Korintus 4:8-9 - "Kami ditindas tetapi tidak terhimpit, dihempaskan tetapi tidak binasa". Remaja teladan tangguh menghadapi masalah'),
(22, 'Kesederhanaan', 'KEPRIBADIAN (Love, Sex, Dating)', 'Hidup tidak berlebihan dan tidak bergantung pada materi. Contoh: Tidak memaksakan orang tua membeli HP mahal hanya karena ikut-ikutan teman.', '1 Timotius 6:6 - "Ibadah disertai rasa cukup adalah keuntungan besar". Remaja teladan bersyukur dengan apa yang ada'),
(23, 'Tenggang Rasa', 'KEPRIBADIAN (Love, Sex, Dating)', 'Memperhatikan perasaan orang lain. Contoh: Tidak berbicara keras di tempat ibadah, tidak mengganggu teman yang sedang belajar.', 'Matius 7:12 - "Segala sesuatu yang kamu kehendaki supaya orang perbuat kepadamu, perbuatlah demikian kepada mereka". Emas benar'),
(24, 'Kemandirian', 'KEPRIBADIAN (Love, Sex, Dating)', 'Mampu melakukan sesuatu tanpa tergantung orang lain. Contoh: Mengerjakan tugas sekolah sendiri, tidak menyuruh orang tua.', 'Remaja teladan belajar bertanggung jawab atas hidupnya sendiri, tidak selalu minta dibantu'),
(25, 'Kreativitas', 'KEPRIBADIAN (Love, Sex, Dating)', 'Kemampuan menciptakan hal baru yang bermanfaat. Contoh: Membuat konten Alkitab di TikTok untuk menjangkau teman-teman sebaya.', 'Keluaran 35:31 - "Telah memenuhinya dengan Roh Allah, dengan keahlian, pengertian, dan pengetahuan". Remaja teladan menggunakan kreativitas untuk kemuliaan Tuhan'),
(26, 'Kepedulian Sosial', 'KEPRIBADIAN (Love, Sex, Dating)', 'Peka terhadap kebutuhan orang lain. Contoh: Menggalang dana untuk korban bencana, menjenguk teman yang sakit.', 'Yakobus 2:16 - "Berikanlah kepada mereka apa yang mereka perlukan". Remaja teladan tidak acuh pada sesama'),
(27, 'Kesetiaan', 'KEPRIBADIAN (Love, Sex, Dating)', 'Tetap komitmen dalam hubungan dan janji. Contoh: Tetap datang ke latihan paduan suara meski lelah, karena sudah berkomitmen.', 'Amsal 20:6 - "Orang yang setia, siapakah menemukannya?". Remaja teladan dapat diandalkan'),
(28, 'Kesopanan', 'KEPRIBADIAN (Love, Sex, Dating)', 'Berperilaku sesuai norma yang berlaku. Contoh: Berpakaian rapi dan sopan saat ke gereja, tidak memakai baju ketat atau pendek.', '1 Timotius 2:9 - "Hendaklah perempuan berdandan dengan pantas, dengan sopan dan sederhana". Berlaku juga untuk pria'),
(29, 'Penerimaan Diri', 'KEPRIBADIAN (Love, Sex, Dating)', 'Menerima kelebihan dan kekurangan diri. Contoh: Tidak iri dengan fisik teman yang lebih menarik, bersyukur dengan apa yang Tuhan beri.', 'Mazmur 139:14 - "Aku bersyukur kepada-Mu karena kejadianku dahsyat dan ajaib". Remaja teladan mengasihi diri sendiri'),
(30, 'Komitmen', 'KEPRIBADIAN (Love, Sex, Dating)', 'Teguh pada keputusan yang telah dibuat. Contoh: Konsisten mengikuti kegiatan remaja setiap minggu meski banyak godaan.', 'Pengkhotbah 5:4 - "Tunaikanlah nazarmu". Remaja teladan tidak mudah berubah pikiran'),
(31, 'Inisiatif', 'KEPRIBADIAN (Love, Sex, Dating)', 'Melakukan sesuatu tanpa menunggu perintah. Contoh: Membersihkan papan tulis sebelum guru datang, tanpa diminta.', 'Remaja teladan proaktif, tidak pasif menunggu disuruh'),
(32, 'Gigih', 'KEPRIBADIAN (Love, Sex, Dating)', 'Tidak menyerah sebelum mencapai tujuan. Contoh: Terus berlatih pidato meski sering gagal, sampai akhirnya bisa.', 'Galatia 6:9 - "Janganlah jemu-jemu berbuat baik, karena pada waktunya kita akan menuai". Remaja teladan tidak mudah menyerah'),
(33, 'Religiusitas', 'KEPRIBADIAN (Love, Sex, Dating)', 'Kedekatan pribadi dengan Tuhan. Contoh: Memiliki waktu teduh setiap hari, berdoa sebelum melakukan apapun.', 'Yakobus 4:8 - "Mendekatlah kepada Allah, maka Ia akan mendekat kepadamu". Remaja teladan memiliki kehidupan rohani yang hidup'),
(34, 'Toleransi', 'KEPRIBADIAN (Love, Sex, Dating)', 'Menghargai perbedaan tanpa mengorbankan iman. Contoh: Berteman baik dengan yang berbeda agama, tidak memaksakan kehendak.', 'Roma 14:19 - "Marilah kita berusaha untuk saling membangun". Remaja teladan hidup rukun dalam perbedaan'),
(35, 'Kritis', 'KEPRIBADIAN (Love, Sex, Dating)', 'Mampu menganalisis informasi dengan bijak. Contoh: Tidak langsung percaya hoaks, mengecek kebenaran berita terlebih dahulu.', '1 Tesalonika 5:21 - "Ujilah segala sesuatu, peganglah yang baik". Remaja teladan cerdas dan tidak mudah termakan hoaks'),
(36, 'Motivasi Diri', 'KEPRIBADIAN (Love, Sex, Dating)', 'Semangat dari dalam diri sendiri. Contoh: Belajar giat karena ingin memuliakan Tuhan, bukan karena takut dimarahi orang tua.', 'Kolose 3:23 - "Apapun juga yang kamu perbuat, perbuatlah dengan segenap hatimu seperti untuk Tuhan". Remaja teladan memiliki motivasi internal'),
(37, 'Kerja Sama', 'KEPRIBADIAN (Love, Sex, Dating)', 'Bekerja bersama mencapai tujuan bersama. Contoh: Membagi tugas kelompok dengan adil, tidak egois.', 'Pengkhotbah 4:9 - "Berdua lebih baik dari seorang diri". Remaja teladan tahu bahwa kebersamaan menguatkan'),
(38, 'Fokus', 'KEPRIBADIAN (Love, Sex, Dating)', 'Memusatkan perhatian pada satu hal. Contoh: Tidak main HP saat belajar, tidak ngobrol saat ibadah.', '1 Korintus 9:24 - "Lari sedemikian rupa sehingga kamu memperolehnya". Remaja teladan tidak terpecah perhatiannya'),
(39, 'Ketenangan', 'KEPRIBADIAN (Love, Sex, Dating)', 'Tidak mudah gelisah dan cemas. Contoh: Menyerahkan kekhawatiran ujian kepada Tuhan dalam doa, belajar maksimal, dan percaya hasilnya.', 'Filipi 4:6-7 - "Janganlah hendaknya kamu kuatir tentang apapun juga". Remaja teladan memiliki damai sejahtera Kristus'),
(40, 'Kebijaksanaan', 'KEPRIBADIAN (Love, Sex, Dating)', 'Kemampuan mengambil keputusan terbaik. Contoh: Memilih menolak ajakan tawuran karena tahu risikonya, mengajak damai.', 'Amsal 4:7 - "Perolehlah hikmat, perolehlah pengertian". Remaja teladan tidak gegabah dalam mengambil keputusan'),
(41, 'Rendah Hati', 'KEPRIBADIAN (Love, Sex, Dating)', 'Tidak sombong atas prestasi. Contoh: Tetap rendah hati meski juara kelas, tidak merendahkan teman.', 'Amsal 16:19 - "Lebih baik merendahkan diri dengan orang yang rendah hati". Remaja teladan tahu semua prestasi adalah anugerah Tuhan'),
(42, 'Teguh Pendirian', 'KEPRIBADIAN (Love, Sex, Dating)', 'Tidak mudah terpengaruh bujukan negatif. Contoh: Tetap tidak merokok meski diajak teman berkali-kali, konsisten dengan prinsip.', 'Efesus 6:14 - "Berdirilah teguh, berikatpinggangkan kebenaran". Remaja teladan memiliki prinsip yang kokoh'),
(43, 'Murah Hati', 'KEPRIBADIAN (Love, Sex, Dating)', 'Senang memberi dan berbagi. Contoh: Memberi sebagian uang jajan untuk teman yang kurang mampu.', 'Amsal 11:25 - "Siapa banyak memberi berkat, diberi kelimpahan". Remaja teladan tidak pelit'),
(44, 'Pemberani', 'KEPRIBADIAN (Love, Sex, Dating)', 'Berani mengungkapkan kebenaran. Contoh: Berani melaporkan tindakan bullying yang dilihatnya kepada guru.', 'Amsal 28:1 - "Orang benar berani seperti singa". Remaja teladan tidak takut membela yang benar'),
(45, 'Humble', 'KEPRIBADIAN (Love, Sex, Dating)', 'Kerendahan hati yang tulus. Contoh: Mengakui kesalahan di depan teman-teman, meminta maaf.', 'Mikha 6:8 - "Berjalanlah dengan rendah hati di hadapan Allahmu". Remaja teladan tidak gengsi mengakui salah'),
(46, 'Grit (Ketekunan Berbasis Gairah)', 'KEPRIBADIAN (Love, Sex, Dating)', 'Ketekunan jangka panjang untuk mencapai tujuan. Contoh: Berlatih musik bertahun-tahun untuk bisa melayani sebagai pemain keyboard di gereja.', 'Remaja teladan memiliki semangat yang tidak padam dalam jangka panjang'),
(47, 'Akuntabilitas', 'KEPRIBADIAN (Love, Sex, Dating)', 'Kesediaan dipertanggungjawabkan dan diawasi. Contoh: Memiliki sahabat rohani yang saling mengingatkan dalam doa dan perilaku.', 'Remaja teladan tidak hidup sendiri, tetapi terbuka pada pertanggungjawaban'),
(48, 'Wisdom', 'KEPRIBADIAN (Love, Sex, Dating)', 'Aplikasi pengetahuan dalam kehidupan nyata. Contoh: Tahu bahwa pacaran di usia remaja rawan dosa, jadi memilih fokus studi dan pelayanan dulu.', 'Amsal 9:10 - "Permulaan hikmat adalah takut akan Tuhan". Remaja teladan tidak hanya tahu, tetapi melakukan'),
(49, 'Self-Esteem Sehat', 'KEPRIBADIAN (Love, Sex, Dating)', 'Menghargai diri tanpa sombong. Contoh: Percaya diri tampil di depan umum karena tahu Tuhan memberi kemampuan, tidak minder.', 'Roma 12:3 - "Janganlah kamu memikirkan hal-hal yang lebih tinggi dari pada yang patut kamu pikirkan". Remaja teladan memiliki pandangan yang seimbang tentang diri'),
(50, 'Pemecah Masalah', 'KEPRIBADIAN (Love, Sex, Dating)', 'Mampu mencari solusi kreatif untuk masalah. Contoh: Ketika sound system gereja rusak saat ibadah, mencari alternatif menggunakan speaker HP.', 'Remaja teladan tidak panik saat masalah datang, tetapi mencari jalan keluar'),
(51, 'Keteladanan Daniel', 'PENGETAHUAN ALKITAB', 'Daniel berani tidak menajiskan diri dengan makanan raja, tetap berdoa 3x sehari meski dilarang. Contoh: Seperti Daniel, remaja teladan tetap berdoa di sekolah meski teman-teman mengejek.', 'Daniel 1:8; 6:10. Daniel menunjukkan bahwa iman tidak bisa dikompromikan. Tuhan melindungi Daniel di gua singa karena kesetiaannya'),
(52, 'Keteladanan Timotius', 'PENGETAHUAN ALKITAB', 'Timotius menjadi teladan sekalipun masih muda, mengikuti Paulus dalam misi, dan melayani dengan setia. Contoh: Remaja teladan aktif dalam pelayanan gereja meski masih muda, menjadi contoh bagi adik-adiknya.', '1 Timotius 4:12 - "Jangan seorang pun menganggap engkau rendah karena engkau muda". Usia bukan penghalang untuk menjadi berkat'),
(53, 'Keteladanan Yusuf', 'PENGETAHUAN ALKITAB', 'Yusuf setia kepada Tuhan saat digoda istri Potifar, tetap jujur meski dipenjara, mengampuni saudara-saudaranya. Contoh: Remaja teladan menolak ajakan pacar untuk berbuat dosa, meski berisiko putus.', 'Kejadian 39:9 - "Bagaimana mungkin aku melakukan kejahatan besar ini dan berdosa terhadap Allah?" Integritas Yusuf membawanya menjadi pemimpin Mesir'),
(54, 'Keteladanan Daud', 'PENGETAHUAN ALKITAB', 'Daud muda berani melawan Goliat karena percaya Tuhan lebih besar. Contoh: Remaja teladan berani melawan ketidakadilan di sekolah meski sendirian, karena percaya Tuhan menyertai.', '1 Samuel 17:45 - "Kepadamu aku mendekat demi nama TUHAN semesta alam". Daud tidak melihat besar masalah, tetapi besar Tuhan-nya'),
(55, 'Keteladanan Rut', 'PENGETAHUAN ALKITAB', 'Rut setia mendampingi Naomi (mertuanya) dan meninggalkan tanah kelahirannya. Contoh: Remaja teladan setia membantu orang tua yang sakit, tidak meninggalkan mereka.', 'Rut 1:16 - "Bangsamulah bangsaku, Allahmulah Allahku". Kesetiaan Rut dibalas Tuhan dengan menjadi nenek moyang Yesus'),
(56, 'Amanat Agung', 'PENGETAHUAN ALKITAB', 'Perintah Yesus untuk pergi, jadikan semua bangsa murid, baptis, dan ajarkan perintah-Nya. Contoh: Remaja teladan mengajak teman sekolah ke gereja dan menjelaskan Injil dengan cara yang relevan.', 'Matius 28:19-20. Ini adalah mandat utama gereja. Setiap remaja teladan adalah missioner di mana pun berada'),
(57, 'Perumpamaan Talenta', 'PENGETAHUAN ALKITAB', 'Setiap orang diberi karunia sesuai kemampuan, harus dikembangkan, bukan disembunyikan. Contoh: Remaja teladan mengikuti lomba pidato untuk mengembangkan bakat bicaranya bagi Tuhan.', 'Matius 25:14-30. Talenta bukan hanya uang tetapi semua karunia Tuhan. Yang penting adalah setia, bukan seberapa besar'),
(58, 'Perumpamaan Orang Samaria yang Baik', 'PENGETAHUAN ALKITAB', 'Kasih tanpa memandang suku, agama, ras. Contoh: Remaja teladan menolong korban kecelakaan meski berbeda agama.', 'Lukas 10:25-37. Siapapun sesama kita yang membutuhkan pertolongan. Kasih Kristus melampaui batas-batas manusia'),
(59, 'Perumpamaan Anak yang Hilang', 'PENGETAHUAN ALKITAB', 'Kasih Bapa yang selalu menanti pertobatan anak-Nya. Contoh: Remaja teladan yang pernah tersesat, kembali kepada Tuhan dan diterima dengan sukacita.', 'Lukas 15:11-32. Tidak ada dosa yang terlalu besar untuk diampuni. Tuhan selalu membuka tangan bagi yang bertobat'),
(60, 'Khotbah di Bukit', 'PENGETAHUAN ALKITAB', 'Ucapan bahagia, garam dan terang, hukum Taurat, doa, puasa, tidak kuatir. Contoh: Remaja teladan menjadi "terang" dengan berperilaku baik di sekolah sehingga teman-teman terinspirasi.', 'Matius 5-7. Ini adalah manifesto Kerajaan Allah. Remaja teladan hidup dengan nilai-nilai yang berbeda dari dunia'),
(61, 'Buah Roh', 'PENGETAHUAN ALKITAB', 'Kasih, sukacita, damai sejahtera, kesabaran, kemurahan, kebaikan, kesetiaan, kelemahlembutan, penguasaan diri. Contoh: Remaja teladan menunjukkan kesabaran saat menghadapi teman yang menjengkelkan.', 'Galatia 5:22-23. Buah Roh adalah karakter Kristus yang dihasilkan Roh Kudus dalam hidup orang percaya'),
(62, 'Karunia Roh', 'PENGETAHUAN ALKITAB', 'Kemampuan khusus dari Roh Kudus untuk melayani: bernubuat, melayani, mengajar, menasihati, memberi, memimpin, menunjukkan kemurahan. Contoh: Remaja teladan menggunakan karunia mengajarnya untuk mengajar Sekolah Minggu.', '1 Korintus 12. Setiap remaja memiliki karunia unik. Tidak ada karunia yang lebih hebat; semua untuk membangun tubuh Kristus'),
(63, 'Iman', 'PENGETAHUAN ALKITAB', 'Dasar dari segala sesuatu yang diharapkan, bukti dari segala sesuatu yang tidak dilihat. Contoh: Remaja teladan tetap percaya Tuhan akan memulihkan orang tuanya yang sakit, meski kondisi belum membaik.', 'Ibrani 11:1. Iman bukan perasaan tetapi keputusan untuk percaya pada janji Tuhan walau keadaan berkata lain'),
(64, 'Pengharapan', 'PENGETAHUAN ALKITAB', 'Keyakinan akan janji Tuhan di masa depan. Contoh: Remaja teladan tidak putus asa meski nilai ujian jelek, karena percaya masa depan ada di tangan Tuhan.', 'Roma 15:13 - "Pengharapan oleh kuasa Roh Kudus". Pengharapan Kristen bukan optimisme kosong tetapi keyakinan pada kesetiaan Tuhan'),
(65, 'Kasih Agape', 'PENGETAHUAN ALKITAB', 'Kasih tanpa syarat yang berasal dari Allah. Contoh: Remaja teladan tetap mengasihi teman yang menghianatinya, mendoakannya bukan membalas dendam.', '1 Korintus 13:1-13. Kasih agape tidak tergantung pada objek yang dikasihi, tetapi sumbernya yaitu Tuhan'),
(66, 'Pengampunan', 'PENGETAHUAN ALKITAB', 'Melepaskan hak untuk membalas dendam. Contoh: Remaja teladan memaafkan teman yang menyebarkan gosip tentangnya, tidak menyimpan dendam.', 'Matius 18:21-22 - "Aku berkata kepadamu: Bukan sampai 7 kali, tetapi sampai 70 x 7 kali". Pengampunan tanpa batas'),
(67, 'Perjanjian Baru', 'PENGETAHUAN ALKITAB', 'Perjanjian yang ditulis dalam hati, bukan di batu, digenapi dalam darah Yesus. Contoh: Remaja teladan hidup bukan karena takut hukum Taurat, tetapi karena kasih kepada Tuhan yang menulis firman di hatinya.', 'Yeremia 31:31-34; Lukas 22:20. Hubungan bukan lagi aturan mati, tetapi relasi pribadi dengan Tuhan'),
(68, 'Tritunggal', 'PENGETAHUAN ALKITAB', 'Satu Allah dalam tiga Pribadi: Bapa, Anak, Roh Kudus. Contoh: Remaja teladan berdoa kepada Bapa, dalam nama Yesus, oleh kuasa Roh Kudus.', 'Matius 28:19 - "Baptislah mereka dalam nama Bapa, Anak, dan Roh Kudus". Bukan tiga Tuhan tetapi satu hakikat'),
(69, 'Keselamatan', 'PENGETAHUAN ALKITAB', 'Anugerah Allah melalui iman dalam Yesus Kristus, bukan karena perbuatan baik. Contoh: Remaja teladan tidak sombong karena rajin ke gereja, tahu bahwa keselamatan adalah pemberian Tuhan.', 'Efesus 2:8-9. Tidak ada yang bisa membanggakan dirinya di hadapan Tuhan. Keselamatan adalah kasih karunia semata'),
(70, 'Salib', 'PENGETAHUAN ALKITAB', 'Simbol pengorbanan Yesus untuk menebus dosa manusia. Contoh: Remaja teladan memikul "salib" dengan rela berkorban waktu dan tenaga untuk melayani.', '1 Petrus 2:24 - "Ia sendiri telah memikul dosa kita di dalam tubuh-Nya di kayu salib". Salib adalah pusat iman Kristen'),
(71, 'Kebangkitan', 'PENGETAHUAN ALKITAB', 'Yesus bangkit dari kematian pada hari ketiga, mengalahkan maut. Contoh: Remaja teladan tidak takut mati karena percaya pada kebangkitan dan hidup kekal.', '1 Korintus 15:17 - "Jika Kristus tidak dibangkitkan, sia-sialah kepercayaanmu". Kebangkitan adalah jaminan kemenangan kita'),
(72, 'Kenaikan Yesus', 'PENGETAHUAN ALKITAB', 'Yesus naik ke surga dan duduk di sebelah kanan Bapa. Contoh: Remaja teladan hidup dengan pengharapan bahwa Yesus akan kembali.', 'Kisah Para Rasul 1:9-11. Yesus naik ke surga dan akan kembali dengan cara yang sama. Kita menantikan kedatangan-Nya'),
(73, 'Roh Kudus', 'PENGETAHUAN ALKITAB', 'Penolong, Penghibur, Guru yang dijanjikan Yesus. Contoh: Remaja teladan meminta tuntunan Roh Kudus saat akan mengambil keputusan penting.', 'Yohanes 14:26. Roh Kudus adalah pribadi, bukan kekuatan abstrak. Ia aktif dalam hidup orang percaya'),
(74, 'Alkitab', 'PENGETAHUAN ALKITAB', 'Firman Tuhan yang diilhamkan, menjadi otoritas tertinggi iman dan kehidupan. Contoh: Remaja teladan membaca Alkitab setiap hari dan menjadikannya pedoman hidup.', '2 Timotius 3:16-17. Alkitab cukup untuk mengajarkan, menyatakan kesalahan, dan memperlengkapi untuk setiap perbuatan baik'),
(75, 'Doa', 'PENGETAHUAN ALKITAB', 'Komunikasi dua arah dengan Tuhan. Contoh: Remaja teladan tidak hanya meminta, tetapi juga mendengarkan suara Tuhan melalui firman dan keheningan.', '1 Tesalonika 5:17 - "Tetaplah berdoa". Doa bukan daftar permintaan tetapi relasi dengan Bapa'),
(76, 'Puasa', 'PENGETAHUAN ALKITAB', 'Menahan diri dari makanan untuk fokus pada Tuhan. Contoh: Remaja teladan berpuasa saat menghadapi ujian penting, memohon hikmat dari Tuhan.', 'Matius 6:16-18. Puasa bukan untuk dilihat orang, tetapi untuk Tuhan. Puasa melatih penguasaan diri'),
(77, 'Persekutuan (Koinonia)', 'PENGETAHUAN ALKITAB', 'Kebersamaan orang percaya dalam iman. Contoh: Remaja teladan aktif dalam kelompok PA (Pemahaman Alkitab) untuk bertumbuh bersama.', 'Kisah Para Rasul 2:42. Orang Kristen tidak hidup sendiri. Persekutuan menguatkan dan saling membangun'),
(78, 'Pelayanan (Diakonia)', 'PENGETAHUAN ALKITAB', 'Melayani sesama sebagai wujud kasih Kristus. Contoh: Remaja teladan mengunjungi panti asuhan dan membagikan makanan kepada yang membutuhkan.', 'Matius 20:28. Yesus datang untuk melayani. Remaja teladan memiliki hati seorang hamba'),
(79, 'Kesaksian (Martyria)', 'PENGETAHUAN ALKITAB', 'Bersaksi tentang Kristus melalui perkataan dan perbuatan. Contoh: Remaja teladan bersaksi dengan menunjukkan perubahan hidup yang lebih baik setelah percaya Yesus.', 'Kisah Para Rasul 1:8. Setiap remaja teladan adalah saksi Kristus di mana pun berada'),
(80, 'Gembala yang Baik', 'PENGETAHUAN ALKITAB', 'Yesus yang mengenal domba-domba-Nya dan memberi nyawa bagi domba. Contoh: Remaja teladan mengenal "suara" Tuhan melalui firman dan tidak mengikuti ajaran sesat.', 'Yohanes 10:11. Yesus bukan gembala upahan. Remaja teladan adalah domba yang mendengar suara Gembala'),
(81, 'Pokok Anggur', 'PENGETAHUAN ALKITAB', 'Yesus adalah pokok, kita adalah ranting. Contoh: Remaja teladan tetap "melekat" pada Yesus melalui doa dan firman agar berbuah.', 'Yohanes 15:5 - "Di luar Aku kamu tidak dapat berbuat apa-apa". Tidak ada keberhasilan rohani tanpa ketergantungan pada Kristus'),
(82, 'Jalan, Kebenaran, Hidup', 'PENGETAHUAN ALKITAB', 'Yesus adalah satu-satunya jalan kepada Bapa. Contoh: Remaja teladan tidak percaya bahwa semua agama sama, tetapi Yesus adalah satu-satunya Juruselamat.', 'Yohanes 14:6. Klaim eksklusif Yesus. Remaja teladan berani menyatakan kebenaran ini dengan kasih'),
(83, 'Terang Dunia', 'PENGETAHUAN ALKITAB', 'Orang percaya adalah terang yang menerangi kegelapan. Contoh: Remaja teladan menjadi teladan di sekolah sehingga teman-teman bertanya tentang imannya.', 'Matius 5:14. Terang tidak bersembunyi. Remaja teladan tidak malu menjadi Kristen'),
(84, 'Garam Dunia', 'PENGETAHUAN ALKITAB', 'Orang percaya memberi "rasa" dan menjadi pengawet di tengah masyarakat. Contoh: Remaja teladan mencegah perundungan (bullying) di sekolah dengan menegur dan mendamaikan.', 'Matius 5:13. Garam yang kehilangan rasa tidak berguna. Remaja teladan harus tetap "asinn" dengan nilai-nilai Kristus'),
(85, 'Pekerjaan Baik', 'PENGETAHUAN ALKITAB', 'Tindakan nyata sebagai buah iman, bukan sarana keselamatan. Contoh: Remaja teladan membantu tetangga yang kesusahan tanpa pamrih, sebagai bukti iman yang hidup.', 'Yakobus 2:17 - "Iman tanpa perbuatan pada hakikatnya adalah mati". Perbuatan baik adalah bukti iman yang sejati'),
(86, 'Pengakuan Iman Rasuli', 'PENGETAHUAN ALKITAB', 'Ringkasan iman Kristen yang diwariskan dari rasul-rasul. Contoh: Remaja teladan hafal dan memahami setiap kalimat Pengakuan Iman Rasuli.', 'Pengakuan iman ini memuat doktrin Tritunggal, inkarnasi, penebusan, kebangkitan, dan hidup kekal'),
(87, 'Pengakuan Iman Nicea', 'PENGETAHUAN ALKITAB', 'Pengakuan iman yang menegaskan ke-Allahan Yesus Kristus. Contoh: Remaja teladan dapat menjelaskan bahwa Yesus sejati Allah dan sejati manusia.', 'Dihasilkan dari Konsili Nicea 325 M untuk melawan ajaran Arian yang menyangkal ke-Allahan Yesus'),
(88, 'Sola Scriptura', 'PENGETAHUAN ALKITAB', 'Hanya Alkitab sebagai otoritas tertinggi iman. Contoh: Remaja teladan menguji setiap ajaran dengan Alkitab, tidak menerima begitu saja.', 'Sola Scriptura adalah slogan Reformasi. Alkitab cukup sebagai sumber ajaran dan pedoman hidup'),
(89, 'Sola Fide', 'PENGETAHUAN ALKITAB', 'Hanya oleh iman seseorang dibenarkan. Contoh: Remaja teladan percaya bahwa perbuatan baik tidak menyelamatkan, tetapi iman kepada Yesus.', 'Roma 3:28. Bukan berarti perbuatan baik tidak penting, tetapi perbuatan baik adalah buah dari iman yang menyelamatkan'),
(90, 'Sola Gratia', 'PENGETAHUAN ALKITAB', 'Hanya oleh kasih karunia, bukan karena usaha manusia. Contoh: Remaja teladan bersyukur karena diselamatkan bukan karena kebaikannya tetapi anugerah Tuhan.', 'Efesus 2:5 - "Karena kasih karunia kamu diselamatkan". Tidak ada yang bisa membanggakan dirinya di hadapan Tuhan'),
(91, 'Solus Christus', 'PENGETAHUAN ALKITAB', 'Hanya Kristus satu-satunya Juruselamat dan Pengantara. Contoh: Remaja teladan berdoa langsung kepada Tuhan dalam nama Yesus, tidak melalui perantara lain.', '1 Timotius 2:5 - "Satu Allah dan satu Pengantara antara Allah dan manusia, yaitu Kristus Yesus"'),
(92, 'Soli Deo Gloria', 'PENGETAHUAN ALKITAB', 'Segala kemuliaan hanya bagi Tuhan. Contoh: Remaja teladan tidak mencari pujian saat tampil di depan umum, tetapi memuliakan Tuhan.', '1 Korintus 10:31 - "Lakukanlah segala sesuatu untuk kemuliaan Allah". Motif pelayanan adalah kemuliaan Tuhan'),
(93, 'Perjamuan Kudus', 'PENGETAHUAN ALKITAB', 'Sakramen peringatan kematian dan kebangkitan Yesus. Contoh: Remaja teladan mempersiapkan hati sebelum menerima Perjamuan Kudus, tidak datang asal-asalan.', '1 Korintus 11:23-26. Roti dan anggur melambangkan tubuh dan darah Kristus yang dikorbankan'),
(94, 'Baptisan Kudus', 'PENGETAHUAN ALKITAB', 'Sakramen tanda perjanjian dan kelahiran baru. Contoh: Remaja teladan yang sudah dibaptis menghidupi janji baptisannya dengan hidup kudus.', 'Matius 28:19. Baptisan bukan hanya ritual tetapi pintu masuk menjadi anggota gereja dan tanda kepatuhan pada Kristus'),
(95, 'Gereja', 'PENGETAHUAN ALKITAB', 'Persekutuan orang percaya yang dipanggil keluar dari dunia. Contoh: Remaja teladan tidak menganggap gereja hanya gedung, tetapi dirinya sendiri adalah gereja di mana pun berada.', 'Efesus 1:22-23. Gereja adalah tubuh Kristus, bukan organisasi tetapi organisme hidup'),
(96, 'Pengudusan', 'PENGETAHUAN ALKITAB', 'Proses menjadi semakin serupa dengan Kristus. Contoh: Remaja teladan terus belajar, berdoa, dan melayani untuk bertumbuh dalam kekudusan.', '1 Tesalonika 4:3 - "Kehendak Allah ialah pengudusanmu". Pengudusan adalah proses seumur hidup, bukan instan'),
(97, 'Pencobaan', 'PENGETAHUAN ALKITAB', 'Ujian iman yang diizinkan Tuhan untuk membentuk karakter. Contoh: Remaja teladan tidak berkecil hati saat gagal, tetapi melihatnya sebagai kesempatan bertumbuh.', 'Yakobus 1:2-4. Pencobaan menghasilkan ketekunan, dan ketekunan menghasilkan kedewasaan rohani'),
(98, 'Anugerah', 'PENGETAHUAN ALKITAB', 'Pemberian Tuhan yang tidak layak kita terima. Contoh: Remaja teladan tidak sombong dengan talentanya, karena semua adalah anugerah Tuhan.', 'Roma 11:6. Anugerah tidak bisa dicampur dengan usaha manusia. Jika karena usaha, bukan lagi anugerah'),
(99, 'Pertobatan', 'PENGETAHUAN ALKITAB', 'Perubahan pikiran dan arah hidup kembali kepada Tuhan. Contoh: Remaja teladan yang sebelumnya malas beribadah, menjadi rajin setelah mengalami pertobatan.', 'Kisah Para Rasul 3:19. Pertobatan sejati ditandai dengan perubahan perilaku, bukan hanya penyesalan'),
(100, 'Kedatangan Tuhan Kedua Kali', 'PENGETAHUAN ALKITAB', 'Yesus akan kembali sebagai Raja dan Hakim. Contoh: Remaja teladan hidup dalam kesucian karena percaya Yesus bisa datang kapan saja.', 'Wahyu 22:12 - "Sesungguhnya Aku datang segera". Kedatangan Yesus adalah pengharapan dan juga peringatan'),
(101, 'GMIM', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Gereja Masehi Injili di Minahasa, gereja mandiri sejak 30 September 1934. Contoh: Remaja teladan bangga menjadi bagian GMIM dan aktif dalam kegiatannya.', 'GMIM adalah gereja Protestan di Sulawesi Utara yang merupakan mandiri dari Indische Kerk. Kata "di" menunjukkan lokasi geografis saat berdiri'),
(102, 'Sistem Presbiterial Sinodal', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Sistem kepemimpinan kolektif para penatua (presbiter) dengan keputusan melalui musyawarah di semua aras. Contoh: Remaja teladan menghargai keputusan rapat komisi remaja yang diambil secara musyawarah.', 'Presbiterial = kepemimpinan para penatua; Sinodal = berjalan bersama. Bukan sistem episkopal (satu uskup) atau kongregasional (independen)'),
(103, 'Aras Pelayanan', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Tingkatan pelayanan: Jemaat (lokal), Wilayah (gabungan jemaat), Sinode (pusat). Contoh: Remaja teladan melayani di aras jemaat sebagai pengurus komisi remaja jemaat.', 'Setiap aras memiliki kewenangan dan tanggung jawab. Keputusan aras bawah tidak boleh bertentangan dengan aras di atasnya'),
(104, 'BPMJ', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Badan Pekerja Majelis Jemaat - pimpinan tertinggi di aras jemaat. Contoh: Remaja teladan mengenal dan menghormati BPMJ di jemaatnya.', 'BPMJ dipimpin oleh Pendeta yang ditempatkan BPMS. Masa pelayanan 5 tahun, mulai 1 Januari sampai 31 Desember'),
(105, 'BPMW', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Badan Pekerja Majelis Wilayah - pimpinan di aras wilayah. Contoh: Remaja teladan berkoordinasi dengan BPMW untuk kegiatan wilayah.', 'BPMW terdiri dari 7 orang: Ketua (Pendeta), Wakil, Sekretaris, Bendahara, 3 Anggota. Masa pelayanan 5 tahun'),
(106, 'BPMS', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Badan Pekerja Majelis Sinode - pimpinan tertinggi GMIM. Contoh: Remaja teladan mendoakan BPMS dalam doa hariannya.', 'BPMS periode 2022-2027 berjumlah 13 orang. Masa pelayanan 5 tahun. Ketua dijabat oleh Pendeta'),
(107, 'Sakramen', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Tanda dan meterai kasih karunia Allah yang kelihatan, terdiri dari Baptisan Kudus dan Perjamuan Kudus. Contoh: Remaja teladan mempersiapkan hati sebelum menerima Perjamuan Kudus.', 'GMIM hanya mengakui 2 sakramen sesuai ajaran Reformasi, bukan 7 sakramen seperti Gereja Katolik'),
(108, 'Baptisan Kudus', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Sakramen tanda perjanjian Allah dan kelahiran baru. Contoh: Remaja teladan yang sudah dibaptis menghidupi janji baptisannya.', 'Dilakukan sekali seumur hidup. Bagi anak-anak berdasarkan iman orang tua; bagi dewasa berdasarkan iman sendiri'),
(109, 'Perjamuan Kudus', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Sakramen peringatan kematian dan kebangkitan Yesus. Contoh: Remaja teladan mengaku dosa sebelum menerima Perjamuan Kudus.', 'Dilayankan oleh Pendeta. Hanya untuk anggota Sidi Jemaat yang sudah mempersiapkan diri. Unsur: roti dan anggur'),
(110, 'Peneguhan Sidi Jemaat', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Pengakuan iman secara dewasa setelah mengikuti katekisasi. Contoh: Remaja teladan yang berusia 17 tahun mengikuti katekisasi untuk menjadi Sidi Jemaat.', 'Minimal usia 17 tahun. Syarat untuk menerima Perjamuan Kudus dan menjadi Pelayan Khusus'),
(111, 'Tata Gereja GMIM 2021', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Aturan dasar kehidupan bergereja yang ditetapkan Sidang Majelis Sinode Istimewa ke-80 (29 Maret 2021). Contoh: Remaja teladan membaca dan memahami Tata Gereja.', 'Terdiri dari 1 Tata Dasar dan 7 Peraturan. Menggantikan Tata Gereja 2016'),
(112, 'KPRS', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Komisi Pelayanan Remaja Sinode - perangkat pelayanan remaja di aras sinode. Contoh: Remaja teladan mengenal program-program KPRS dan berpartisipasi.', 'Berdiri sendiri sejak 28 Januari 1990. Tanggal ini diperingati sebagai Hari Persatuan Remaja GMIM'),
(113, 'KPRJ', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Komisi Pelayanan Remaja Jemaat - perangkat pelayanan remaja di aras jemaat. Contoh: Remaja teladan menjadi pengurus KPRJ di jemaatnya.', 'Pengurus KPRJ adalah Pembina Remaja, bukan remaja itu sendiri. Mereka yang sudah Sidi Jemaat dan memiliki sertifikat LTPR'),
(114, 'LKRG', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Latihan Kader Remaja Gereja - program pembinaan remaja berjenjang. Contoh: Remaja teladan mengikuti LKRG Dasar, Madya, dan Taruna.', 'Tujuannya mempersiapkan kader remaja yang militan, berkarakter Kristus, dan memiliki spiritualitas kuat'),
(115, 'LTPR', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Latihan Tenaga Pembina Remaja - pelatihan untuk menjadi pembina remaja. Contoh: Remaja teladan bercita-cita menjadi pembina remaja setelah cukup usia.', 'Syarat menjadi pengurus KPRJ (Pembina Remaja) adalah memiliki sertifikat LTPR'),
(116, 'Pemilihan Remaja Teladan', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Ajang seleksi remaja teladan melalui berbagai tahapan. Contoh: Remaja teladan mempersiapkan diri untuk mengikuti seleksi ini dengan belajar dan berlatih.', 'Tahapan: Tes Tertulis, Wawancara, Karantina, Pelayanan Holistik, Kompetisi Potensi Diri, Final/Grand Final'),
(117, 'Hari Persatuan Remaja GMIM', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Peringatan berdirinya KPRS yang mandiri, setiap 28 Januari. Contoh: Remaja teladan mengikuti perayaan HPRG di wilayahnya dengan sukacita.', 'Pertama kali diperingati pada 28 Januari 1990 di Palelon Modoinding'),
(118, 'Mars Remaja GMIM', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Lagu wajib dalam kegiatan remaja GMIM. Contoh: Remaja teladan hafal dan menyanyikan Mars Remaja GMIM dengan penuh semangat.', 'Diciptakan oleh Pnt. Jantje Wowiling Sajow. Lagu ini menggambarkan semangat pelayanan remaja'),
(119, 'Lagu "Menjadi Teladan"', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Lagu tema Pemilihan Remaja Teladan, diciptakan Pnt. Ir. Dwight Moody Rondonuwu. Contoh: Remaja teladan menghayati lirik "menjadi teladan" dalam hidupnya.', 'Pertama kali dinyanyikan pada Pemilihan Remaja Teladan Sinode tahun 2015'),
(120, 'Sejarah GMIM - 30 September 1934', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Tanggal GMIM berdiri sendiri sebagai gereja mandiri. Contoh: Remaja teladan memperingati hari jadi GMIM setiap tahun.', 'Berdasarkan Staatsblad Hindia Belanda No. 563/1934, tanggal 17 September 1934, dan berlaku 30 September 1934'),
(121, 'Ds. E.A.A. de Vreede', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Ketua Sinode GMIM pertama (1934-1935). Contoh: Remaja teladan mengenal tokoh sejarah GMIM sebagai bentuk penghargaan.', 'Beliau adalah misionaris Belanda yang memimpin GMIM pada awal berdirinya'),
(122, 'Ds. A.Z.R. Wenas', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Ketua Sinode pribumi pertama (1942-1951, dan 1955-1967). Contoh: Remaja teladan meneladani semangat nasionalisme dan pengabdian beliau.', 'Beliau adalah orang Minahasa pertama yang menjadi Ketua Sinode. Menjabat dua periode'),
(123, 'Pdt. Dr. W.A. Roeroe', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Ketua Sinode terlama (1979-1990 dan 1995-2000). Contoh: Remaja teladan belajar tentang dedikasi beliau yang melayani dalam waktu lama.', 'Total 16 tahun memimpin GMIM. Banyak karya dan pembangunan pada masa pelayanannya'),
(124, 'Misionaris Schwarz & Riedel', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Penginjil Eropa yang memberitakan Injil di Minahasa. Contoh: Remaja teladan bersyukur atas pengorbanan mereka sehingga kita dapat mengenal Yesus.', 'Schwarz melayani di Langowan dan Kakas; Riedel di Tondano. Mereka datang pada abad ke-19'),
(125, 'Lambang GMIM (Manguni)', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Burung Manguni melambangkan gereja sebagai terang di tengah kegelapan. Contoh: Remaja teladan memakai lambang GMIM dengan bangga.', 'Jumlah helai sayap melambangkan tahun 1934 (34 helai). Manguni aktif di malam hari → terang di kegelapan'),
(126, 'Sitou Timou Tumou Tou', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Falsafah Minahasa: "Manusia hidup untuk memanusiakan manusia lain". Contoh: Remaja teladan mengamalkan dengan menolong sesama.', 'Diangkat dari falsafah daerah, menjadi semboyan pelayanan diakonia GMIM'),
(127, 'Mapalus', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Budaya gotong royong Minahasa yang menjadi model pelayanan bersama. Contoh: Remaja teladan bergotong royong membersihkan lingkungan gereja.', 'Nilai luhur budaya yang selaras dengan ajaran Alkitab tentang kebersamaan'),
(128, 'Katekisasi', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Pengajaran iman Kristen secara sistematis. Contoh: Remaja teladan serius mengikuti katekisasi sebelum Sidi.', 'Ada katekisasi Baptisan, Katekisasi Sidi, dan Katekisasi Pernikahan. Materi sesuai kurikulum BPMS'),
(129, 'Pelayan Khusus', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Jabatan gerejawi: Diaken, Penatua, Guru Agama, Pendeta. Contoh: Remaja teladan merindukan untuk menjadi Pelayan Khusus di masa depan.', 'Diaken dan Penatua dipilih untuk periode 5 tahun. Guru Agama dan Pendeta adalah panggilan seumur hidup'),
(130, 'Diaken', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Pelayan yang fokus pada pelayanan diakonia (kasih) dan pengelolaan keuangan. Contoh: Remaja teladan belajar tentang keteladanan Stefanus sebagai Diaken.', 'Kisah Para Rasul 6:1-7. Diaken dipilih untuk melayani kebutuhan jasmani jemaat'),
(131, 'Penatua', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Pelayan yang fokus pada pemberitaan firman, ibadah, dan penggembalaan. Contoh: Remaja teladan menghormati Penatua yang membimbingnya.', '1 Timotius 3:1-7. Penatua harus cakap mengajar dan memiliki kehidupan yang baik'),
(132, 'Pendeta', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Pelayan khusus yang ditahbiskan untuk pemberitaan firman dan pelayanan sakramen. Contoh: Remaja teladan menghormati dan mendoakan pendeta jemaatnya.', 'Memenuhi syarat: pendidikan teologi S-1, masa vikariat 2 tahun, ditetapkan BPMS'),
(133, 'Guru Agama', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Pelayan khusus yang bertugas mengajar Agama Kristen di sekolah. Contoh: Remaja teladan memperhatikan pelajaran Agama Kristen di sekolah.', 'Memenuhi syarat: pendidikan teologi S-1 jurusan PAK, masa vikariat 1 tahun di sekolah'),
(134, 'Pekerja GMIM', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Pendeta, Guru Agama, pegawai yang menerima biaya hidup dari GMIM. Contoh: Remaja teladan mendoakan pekerja GMIM yang melayani dengan setia.', 'Status khusus dengan hak dan kewajiban yang diatur dalam Peraturan tentang Pekerja GMIM'),
(135, 'Komisi Pengawas Perbendaharaan (KPP)', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Perangkat yang mengawasi pengelolaan keuangan di semua aras. Contoh: Remaja teladan mendukung transparansi keuangan gereja.', 'Ada KPPJ (Jemaat), KPPW (Wilayah), KPPS (Sinode). Bertugas mengawasi, memeriksa, membina'),
(136, 'Atribut GMIM', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Lambang, stempel, papan nama, pakaian jabatan, toga, stola. Contoh: Remaja teladan mengenakan pakaian sopan saat beribadah.', 'Toga putih untuk persekutuan dengan kematian dan kebangkitan Kristus. Stola sesuai tahun gerejawi'),
(137, 'Tahun Gerejawi', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Siklus tahunan perayaan iman Kristen: Adven, Natal, Epifania, Pra-Paskah, Paskah, Pentakosta. Contoh: Remaja teladan memahami makna setiap hari raya gerejawi.', 'Digunakan untuk menentukan warna liturgi dan bacaan Alkitab'),
(138, 'MTPJ', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Materi Pembacaan dan Tanggung Jawab Pelayanan Jemaat - bacaan Alkitab mingguan warga GMIM. Contoh: Remaja teladan membaca MTPJ setiap hari untuk merenungkan firman.', 'Diterbitkan oleh BPMS. Bacaan Alkitah untuk ibadah harian dan mingguan'),
(139, 'Kelompok Pelayanan Lansia', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Perangkat pelayanan bagi warga jemaat usia 60 tahun ke atas. Contoh: Remaja teladan menghormati lansia dan melayani mereka dengan sukacita.', 'Setiap aras (Jemaat, Wilayah, Sinode) memiliki Kelompok Pelayanan Lansia'),
(140, 'Peraturan tentang Jemaat', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Bagian dari Tata Gereja yang mengatur kehidupan di aras jemaat. Contoh: Remaja teladan mengetahui Bab IX Pasal 31 Ayat 4d tentang usia remaja.', 'Pasal 31 Ayat 4d: Remaja adalah anggota GMIM usia 12-16 tahun 364 hari'),
(141, 'Peraturan tentang Wilayah', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Bagian dari Tata Gereja yang mengatur pelayanan di aras wilayah. Contoh: Remaja teladan mengetahui struktur pelayanan di wilayahnya.', 'Mengatur tentang BPMW, Komisi Pelayanan Kategorial Wilayah, dll'),
(142, 'Peraturan tentang Sinode', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Bagian dari Tata Gereja yang mengatur pelayanan di aras sinode. Contoh: Remaja teladan mengetahui bahwa BPMS dipilih setiap 5 tahun.', 'Mengatur tentang BPMS, Sidang Majelis Sinode, pemilihan, dll'),
(143, 'Sidang Majelis Sinode', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Pengambilan keputusan tertinggi di GMIM. Contoh: Remaja teladan mendoakan kelancaran sidang sinode.', 'Terdiri dari Sidang 5 tahunan, Sidang Tahunan, dan Sidang Istimewa'),
(144, 'PGI', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Persekutuan Gereja-Gereja di Indonesia - wadah oikumenis gereja Protestan di Indonesia. Contoh: Remaja teladan mendukung kerjasama antar gereja.', 'GMIM adalah anggota PGI. Kerjasama dalam kesaksian dan pelayanan di tingkat nasional'),
(145, 'NZG', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Nederlands Zendeling Genootschap - lembaga penginjilan Belanda yang mengutus misionaris ke Minahasa. Contoh: Remaja teladan bersyukur atas peran NZG dalam penginjilan.', 'Mengutus Schwarz, Riedel, dan misionaris lainnya ke Minahasa pada abad ke-19'),
(146, 'Indische Kerk', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Gereja Hindia Belanda yang menjadi cikal bakal GMIM sebelum kemandirian. Contoh: Remaja teladan mempelajari sejarah kemandirian GMIM dari Indische Kerk.', 'GMIM adalah gereja mandiri yang lahir dari Indische Kerk pada 1934'),
(147, 'Pengakuan Iman GMIM', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Dasar iman yang diakui GMIM: Pengakuan Iman Rasuli, Nicea-Konstantinopel, Athanasius, PBIK. Contoh: Remaja teladan menghafal dan memahami Pengakuan Iman Rasuli.', 'Dalam persekutuan dengan gereja di segala abad, GMIM mengakui pengakuan iman oikumenis'),
(148, 'Pembina Remaja', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Anggota Sidi Jemaat yang melayani dan membina remaja, telah mengikuti LTPR. Contoh: Remaja teladan menghormati Pembina Remaja sebagai pembimbing.', 'Syarat menjadi pengurus KPRJ adalah Pembina Remaja, bukan remaja aktif'),
(149, 'Regenerasi', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Proses kaderisasi untuk menghasilkan pemimpin penerus. Contoh: Remaja teladan mempersiapkan diri menjadi pemimpin masa depan gereja.', 'KPRS memiliki program LKRG untuk mempersiapkan kader remaja'),
(150, 'Gereja Global', 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'GMIM sebagai gereja yang melayani tidak hanya di Minahasa tetapi di seluruh dunia. Contoh: Remaja teladan mendukung misi GMIM ke luar negeri.', 'GMIM kini memiliki jemaat di berbagai provinsi di Indonesia dan di luar negeri (Belanda, Amerika, dll)'),
(151, 'Servant Leadership', 'KEPEMIMPINAN DAN ORGANISASI', 'Kepemimpinan yang mengutamakan pelayanan, bukan kekuasaan. Contoh: Ketua remaja yang ikut membersihkan ruangan, bukan hanya menyuruh.', 'Model kepemimpinan Yesus (Markus 10:45). Pemimpin yang melayani akan dihormati, bukan ditakuti'),
(152, 'Visi', 'KEPEMIMPINAN DAN ORGANISASI', 'Gambaran masa depan yang ingin dicapai bersama. Contoh: Remaja teladan memiliki visi "Remaja Bagi Kristus" dalam setiap kegiatannya.', 'Visi memberi arah. Tanpa visi, organisasi kehilangan fokus. Visi KPRS: "Remaja Bagi Kristus"'),
(153, 'Misi', 'KEPEMIMPINAN DAN ORGANISASI', 'Langkah-langkah strategis untuk mencapai visi. Contoh: Remaja teladan mengikuti LKRG sebagai bagian dari misi menjadi remaja yang bertumbuh.', 'Misi KPRS: Menjadikan remaja GMIM yang berakar, bertumbuh, dan berbuah bagi Kristus'),
(154, 'Organisasi', 'KEPEMIMPINAN DAN ORGANISASI', 'Wadah kerjasama sekelompok orang untuk mencapai tujuan bersama. Contoh: Remaja teladan aktif dalam organisasi remaja gereja untuk belajar bekerja sama.', 'Organisasi melatih tanggung jawab, kerjasama, dan kepemimpinan. Remaja perlu berorganisasi'),
(155, 'Regenerasi', 'KEPEMIMPINAN DAN ORGANISASI', 'Proses kaderisasi untuk mempersiapkan pemimpin penerus. Contoh: Remaja teladan melatih adik kelas untuk bisa menggantikannya nanti.', 'Pemimpin yang baik meninggalkan pewaris. Jangan takut digantikan, tetapi persiapkan pengganti'),
(156, 'Delegasi', 'KEPEMIMPINAN DAN ORGANISASI', 'Pemberian wewenang dan tanggung jawab kepada orang lain. Contoh: Ketua remaja mendelegasikan tugas koordinator acara kepada wakilnya.', 'Delegasi bukan melepas tanggung jawab, tetapi memberdayakan orang lain. Pemimpin tidak bisa mengerjakan semuanya sendiri'),
(157, 'Koordinasi', 'KEPEMIMPINAN DAN ORGANISASI', 'Pengaturan kerja sama antar bagian agar selaras. Contoh: Remaja teladan mengkoordinasikan jadwal latahan paduan suara dengan pemusik.', 'Koordinasi mencegah tumpang tindih dan konflik. Komunikasi yang baik adalah kunci koordinasi'),
(158, 'Musyawarah', 'KEPEMIMPINAN DAN ORGANISASI', 'Pengambilan keputusan bersama melalui diskusi untuk mencapai mufakat. Contoh: Remaja teladan menghargai pendapat semua anggota dalam rapat, tidak memaksakan kehendak.', 'Sesuai sistem Presbiterial Sinodal. Musyawarah mufakat adalah nilai luhur bangsa dan gereja'),
(159, 'Konflik', 'KEPEMIMPINAN DAN ORGANISASI', 'Perbedaan pendapat yang tidak dikelola dengan baik. Contoh: Remaja teladan menjadi mediator saat dua temannya berselisih.', 'Konflik itu normal. Yang penting adalah cara mengelolanya dengan bijak dan kasih'),
(160, 'Mediasi', 'KEPEMIMPINAN DAN ORGANISASI', 'Proses penyelesaian konflik dengan bantuan pihak ketiga yang netral. Contoh: Ketua remaja menjadi mediator antara bendahara dan seksi acara yang berselisih soal dana.', 'Matius 5:9 - "Berbahagialah pembawa damai". Remaja teladan menjadi pendamai, bukan pemicu konflik'),
(161, 'Motivasi', 'KEPEMIMPINAN DAN ORGANISASI', 'Dorongan dari dalam atau luar untuk bertindak. Contoh: Remaja teladan memotivasi teman yang malas dengan memberi semangat dan contoh.', 'Pemimpin hebat adalah motivator. Mereka menginspirasi, bukan memaksa'),
(162, 'Disiplin Organisasi', 'KEPEMIMPINAN DAN ORGANISASI', 'Ketaatan pada aturan dan komitmen yang disepakati. Contoh: Remaja teladan datang tepat waktu setiap rapat, tidak pernah terlambat.', 'Disiplin adalah bentuk penghargaan pada orang lain dan pada organisasi'),
(163, 'Evaluasi', 'KEPEMIMPINAN DAN ORGANISASI', 'Penilaian terhadap pelaksanaan program untuk perbaikan ke depan. Contoh: Remaja teladan mengadakan evaluasi setelah kegiatan Paskah untuk mengetahui kekurangan.', 'Evaluasi bukan untuk mencari kesalahan, tetapi untuk belajar dan berkembang'),
(164, 'Kaderisasi', 'KEPEMIMPINAN DAN ORGANISASI', 'Proses pembinaan kader secara berkelanjutan. Contoh: Remaja teladan mengikuti LKRG sebagai proses kaderisasi di GMIM.', 'Kaderisasi menjamin keberlangsungan organisasi. Tanpa kaderisasi, organisasi akan mati'),
(165, 'Mentoring', 'KEPEMIMPINAN DAN ORGANISASI', 'Pendampingan oleh orang yang lebih berpengalaman. Contoh: Remaja teladan memiliki pembina rohani yang membimbingnya.', 'Amsal 27:17 - "Besi menajamkan besi". Mentoring mempercepat pertumbuhan dan mencegah kesalahan'),
(166, 'Teamwork', 'KEPEMIMPINAN DAN ORGANISASI', 'Kerjasama tim untuk mencapai tujuan bersama. Contoh: Remaja teladan membagi tugas dengan adil dan membantu yang kesulitan.', 'Tidak ada pemimpin yang sukses tanpa tim yang solid. Teamwork membuat pekerjaan berat menjadi ringan'),
(167, 'Pengambilan Keputusan', 'KEPEMIMPINAN DAN ORGANISASI', 'Proses memilih alternatif terbaik dari beberapa pilihan. Contoh: Remaja teladan melibatkan tim dalam pengambilan keputusan, tidak otoriter.', 'Keputusan yang baik adalah keputusan yang melibatkan banyak pihak dan mempertimbangkan dampak'),
(168, 'Manajemen Waktu', 'KEPEMIMPINAN DAN ORGANISASI', 'Pengaturan waktu secara efektif dan efisien. Contoh: Remaja teladan membuat jadwal harian: belajar, ibadah, istirahat, dan bermain seimbang.', 'Waktu adalah anugerah Tuhan yang tidak bisa diulang. Remaja teladan adalah pengelola waktu yang baik'),
(169, 'Skala Prioritas', 'KEPEMIMPINAN DAN ORGANISASI', 'Menentukan mana yang lebih penting dan mendesak. Contoh: Remaja teladan memprioritaskan ibadah Minggu daripada jalan-jalan dengan teman.', 'Matius 6:33 - "Carilah dahulu Kerajaan Allah". Prioritas utama adalah Tuhan, baru yang lain'),
(170, 'Proaktif', 'KEPEMIMPINAN DAN ORGANISASI', 'Bertindak sebelum diminta/disuruh. Contoh: Remaja teladan membersihkan papan tulis sebelum guru datang, tanpa diminta.', 'Pemimpin proaktif tidak menunggu masalah datang, tetapi mencegahnya. Inisiatif adalah ciri pemimpin'),
(171, 'Problem Solving', 'KEPEMIMPINAN DAN ORGANISASI', 'Kemampuan mencari solusi atas masalah. Contoh: Remaja teladan mencari alternatif tempat latihan saat gereja sedang direnovasi.', 'Pemimpin adalah pemecah masalah, bukan pengeluh. Setiap masalah pasti ada solusinya'),
(172, 'Komunikasi Efektif', 'KEPEMIMPINAN DAN ORGANISASI', 'Penyampaian pesan yang jelas dan dipahami dengan baik. Contoh: Remaja teladan berbicara dengan jelas dan mendengarkan dengan aktif saat rapat.', 'Komunikasi yang buruk adalah sumber utama konflik. Komunikasi yang baik membangun hubungan'),
(173, 'Kepemimpinan Situasional', 'KEPEMIMPINAN DAN ORGANISASI', 'Gaya kepemimpinan yang disesuaikan dengan situasi dan kematangan tim. Contoh: Remaja teladan memberikan arahan detail kepada anggota baru, tetapi memberi kebebasan kepada yang sudah berpengalaman.', 'Tidak ada gaya kepemimpinan yang cocok untuk semua situasi. Pemimpin yang baik fleksibel'),
(174, 'Pengawasan', 'KEPEMIMPINAN DAN ORGANISASI', 'Pemantauan pelaksanaan tugas untuk memastikan sesuai rencana. Contoh: Ketua remaja memantau persiapan acara tanpa ikut campur terlalu banyak.', 'Pengawasan bukan berarti tidak percaya, tetapi bentuk tanggung jawab. Kontrol yang berlebihan mematikan kreativitas'),
(175, 'Krisis Kepemimpinan', 'KEPEMIMPINAN DAN ORGANISASI', 'Situasi di mana organisasi kehilangan arah karena lemahnya kepemimpinan. Contoh: Remaja teladan mencegah krisis dengan mempersiapkan kader sejak dini.', 'Krisis kepemimpinan terjadi ketika tidak ada regenerasi. Solusinya: kaderisasi yang baik'),
(176, 'Keteladanan', 'KEPEMIMPINAN DAN ORGANISASI', 'Pemimpin menjadi contoh yang baik bagi yang dipimpin. Contoh: Ketua remaja datang lebih awal dan pulang paling akhir setiap kegiatan.', '1 Timotius 4:12 - "Jadilah teladan". Orang lebih mendengar apa yang kita lakukan daripada apa yang kita katakan'),
(177, 'Otoritas', 'KEPEMIMPINAN DAN ORGANISASI', 'Kewenangan yang sah untuk mengambil keputusan dan memerintah. Contoh: Ketua remaja menggunakan otoritasnya untuk memutuskan jadwal rapat, tetapi tetap mendengar masukan.', 'Otoritas diberikan, bukan diambil. Otoritas yang tidak disertai keteladanan adalah kediktatoran'),
(178, 'Pengaruh', 'KEPEMIMPINAN DAN ORGANISASI', 'Kemampuan membujuk tanpa memaksa. Contoh: Remaja teladan mempengaruhi temannya untuk ikut kegiatan gereja dengan ajakan yang baik, bukan paksaan.', 'Pemimpin yang efektif memiliki pengaruh, bukan sekadar kekuasaan. Pengaruh dibangun dari kepercayaan'),
(179, 'Tanggung Jawab', 'KEPEMIMPINAN DAN ORGANISASI', 'Kesediaan menanggung konsekuensi dari keputusan dan tindakan. Contoh: Ketua remaja mengakui kesalahan ketika acara kurang sukses, tidak menyalahkan panitia.', 'Pemimpin sejati tidak mencari kambing hitam. Mereka bertanggung jawab dan belajar dari kesalahan'),
(180, 'Akuntabilitas', 'KEPEMIMPINAN DAN ORGANISASI', 'Kesediaan dipertanggungjawabkan kepada pihak yang berwenang. Contoh: Bendahara remaja membuat laporan keuangan yang transparan dan dapat diaudit.', 'Akuntabilitas adalah bentuk integritas. Pemimpin yang akuntabel dapat dipercaya'),
(181, 'Rapat Efektif', 'KEPEMIMPINAN DAN ORGANISASI', 'Rapat yang tepat waktu, fokus, dan menghasilkan keputusan. Contoh: Remaja teladan membuat agenda rapat sebelum rapat dimulai dan tepat waktu.', 'Rapat yang tidak efektif membuang waktu. Remaja teladan memimpin rapat dengan efisien'),
(182, 'Notulensi', 'KEPEMIMPINAN DAN ORGANISASI', 'Catatan resmi jalannya rapat dan keputusan yang diambil. Contoh: Sekretaris remaja membuat notulensi setiap rapat sebagai dokumentasi.', 'Notulensi mencegah kesalahpahaman dan menjadi acuan tindak lanjut. Arsip penting organisasi'),
(183, 'Program Kerja', 'KEPEMIMPINAN DAN ORGANISASI', 'Rencana kegiatan organisasi dalam periode tertentu. Contoh: Remaja teladan menyusun proker (program kerja) awal tahun bersama tim.', 'Proker yang baik spesifik, terukur, dapat dicapai, realistis, dan berbatas waktu (SMART)'),
(184, 'Anggaran', 'KEPEMIMPINAN DAN ORGANISASI', 'Rencana pemasukan dan pengeluaran dana untuk kegiatan. Contoh: Bendahara remaja membuat anggaran sebelum kegiatan agar tidak defisit.', 'Anggaran mencegah pemborosan. Remaja teladan belajar mengelola keuangan dengan bijak'),
(185, 'Laporan Pertanggungjawaban (LPJ)', 'KEPEMIMPINAN DAN ORGANISASI', 'Laporan pelaksanaan program dan keuangan setelah kegiatan. Contoh: Panitia kegiatan Paskah membuat LPJ untuk dipertanggungjawabkan kepada komisi remaja.', 'LPJ adalah bentuk akuntabilitas. Remaja teladan belajar membuat LPJ yang rapi dan jujur'),
(186, 'Rekrutmen', 'KEPEMIMPINAN DAN ORGANISASI', 'Proses mencari dan memilih anggota baru. Contoh: Komisi remaja membuka pendaftaran anggota baru dengan kriteria yang jelas.', 'Rekrutmen yang baik menghasilkan tim yang berkualitas. Remaja teladan membantu proses rekrutmen'),
(187, 'Pembinaan', 'KEPEMIMPINAN DAN ORGANISASI', 'Proses pengembangan potensi anggota secara berkelanjutan. Contoh: Remaja teladan mengikuti pembinaan rohani rutin setiap minggu.', 'Pembinaan mencegah kemandekan. Organisasi yang sehat memiliki sistem pembinaan yang baik'),
(188, 'Retreat', 'KEPEMIMPINAN DAN ORGANISASI', 'Kegiatan penyegaran rohani dan fisik di luar tempat rutin. Contoh: Komisi remaja mengadakan retreat tahunan untuk mempererat kebersamaan.', 'Retreat (perenungan) memulihkan semangat dan memperkuat ikatan tim'),
(189, 'Kebersamaan', 'KEPEMIMPINAN DAN ORGANISASI', 'Rasa persatuan dan kekeluargaan dalam organisasi. Contoh: Remaja teladan makan bersama setelah ibadah untuk mempererat persaudaraan.', 'Kebersamaan adalah lem yang menyatukan tim. Tanpa kebersamaan, organisasi mudah terpecah'),
(190, 'Solidaritas', 'KEPEMIMPINAN DAN ORGANISASI', 'Rasa setia kawan dan saling mendukung. Contoh: Remaja teladan menjenguk teman yang sakit dan membantu meringankan bebannya.', 'Roma 12:15 - "Bersukacitalah dengan orang yang bersukacita, menangislah dengan orang yang menangis"'),
(191, 'Inovasi', 'KEPEMIMPINAN DAN ORGANISASI', 'Ide baru yang kreatif untuk kemajuan organisasi. Contoh: Remaja teladan mengusulkan ibadah online untuk menjangkau remaja yang sibuk.', 'Inovasi membuat organisasi tetap relevan dengan zaman. Remaja teladan tidak takut mencoba hal baru'),
(192, 'Adaptasi', 'KEPEMIMPINAN DAN ORGANISASI', 'Kemampuan menyesuaikan diri dengan perubahan. Contoh: Remaja teladan cepat belajar menggunakan aplikasi baru untuk rapat online saat pandemi.', 'Organisasi yang adaptif bertahan di tengah perubahan. Fleksibilitas adalah kunci kelangsungan hidup'),
(193, 'Krisis', 'KEPEMIMPINAN DAN ORGANISASI', 'Situasi genting yang mengancam kelangsungan organisasi. Contoh: Remaja teladan tetap tenang dan mencari solusi saat pembicara acara batal mendadak.', 'Pemimpin diuji dalam krisis. Yang terlihat bukan kepanikannya, tetapi solusinya'),
(194, 'Manajemen Krisis', 'KEPEMIMPINAN DAN ORGANISASI', 'Strategi menghadapi dan mengatasi krisis. Contoh: Komisi remaja memiliki rencana cadangan (backup plan) untuk setiap kegiatan besar.', 'Siapkan payung sebelum hujan. Remaja teladan antisipatif, bukan reaktif'),
(195, 'Goal Setting', 'KEPEMIMPINAN DAN ORGANISASI', 'Penetapan tujuan yang jelas dan terukur. Contoh: Remaja teladan menetapkan target: 10 teman baru diajak ke gereja dalam 3 bulan.', 'Tujuan yang jelas memberi motivasi dan arah. Tanpa tujuan, organisasi berjalan tanpa arah'),
(196, 'Sumber Daya Manusia (SDM)', 'KEPEMIMPINAN DAN ORGANISASI', 'Potensi manusia yang dimiliki organisasi. Contoh: Remaja teladan mengidentifikasi bakat teman-temannya untuk ditempatkan sesuai kemampuannya.', 'SDM adalah aset paling berharga. Remaja teladan mengembangkan SDM, bukan mengeksploitasi'),
(197, 'Pengembangan Diri', 'KEPEMIMPINAN DAN ORGANISASI', 'Upaya meningkatkan kemampuan diri secara sadar. Contoh: Remaja teladan mengikuti pelatihan kepemimpinan di luar gereja untuk menambah wawasan.', 'Pemimpin yang baik adalah pembelajar seumur hidup. Berhenti belajar berarti berhenti memimpin'),
(198, 'Resolusi Konflik', 'KEPEMIMPINAN DAN ORGANISASI', 'Penyelesaian pertentangan secara damai dan adil. Contoh: Remaja teladan mempertemukan dua anggota yang berselisih untuk berdamai.', 'Matius 5:23-24 - "Berdamailah dahulu dengan saudaramu". Resolusi konflik memulihkan hubungan'),
(199, 'Kepemimpinan Transformatif', 'KEPEMIMPINAN DAN ORGANISASI', 'Kepemimpinan yang mengubah anggota menjadi versi terbaik dirinya. Contoh: Ketua remaja membina anggota sehingga mereka lebih percaya diri dan bertumbuh.', 'Pemimpin transformatif tidak hanya mencapai target, tetapi mengubah hidup orang'),
(200, 'Warisan Kepemimpinan', 'KEPEMIMPINAN DAN ORGANISASI', 'Apa yang ditinggalkan pemimpin setelah masa jabatannya. Contoh: Remaja teladan ingin dikenang sebagai pemimpin yang melayani, bukan hanya populer.', 'Warisan terbaik bukan proyek megah, tetapi orang-orang yang diberdayakan. Apa yang akan kau tinggalkan?'),
(201, 'Bhinneka Tunggal Ika', 'PENGETAHUAN UMUM', 'Semboyan negara Indonesia: "Berbeda-beda tetapi tetap satu". Contoh: Remaja teladan berteman dengan semua suku dan agama tanpa membeda-bedakan.', 'Berasal dari kitab Sutasoma karya Mpu Tantular. Remaja teladan menghayati persatuan dalam keberagaman'),
(202, 'Pancasila', 'PENGETAHUAN UMUM', 'Dasar negara Indonesia: 5 sila. Contoh: Remaja teladan mengamalkan sila pertama dengan taat beribadah.', 'Sila 1: Ketuhanan Yang Maha Esa. Remaja teladan menghormati Pancasila sebagai pemersatu bangsa'),
(203, 'UUD 1945', 'PENGETAHUAN UMUM', 'Konstitusi dasar Negara Kesatuan Republik Indonesia. Contoh: Remaja teladan mengetahui hak dan kewajibannya sebagai warga negara.', 'UUD 1945 adalah hukum tertinggi di Indonesia. Remaja teladan taat pada hukum'),
(204, 'NKRI', 'PENGETAHUAN UMUM', 'Negara Kesatuan Republik Indonesia. Contoh: Remaja teladan bangga menjadi warga NKRI dan ikut menjaganya.', 'Bentuk negara kesatuan dengan desentralisasi. Remaja teladan cinta tanah air'),
(205, 'Proklamasi 17 Agustus 1945', 'PENGETAHUAN UMUM', 'Deklarasi kemerdekaan Indonesia. Contoh: Remaja teladan mengikuti upacara 17 Agustus dengan khidmat.', 'Dibacakan Soekarno-Hatta di Jl. Pegangsaan Timur 56, Jakarta. Puncak perjuangan bangsa'),
(206, 'Soekarno', 'PENGETAHUAN UMUM', 'Presiden pertama Republik Indonesia, Proklamator. Contoh: Remaja teladan mempelajari pidato-pidato Soekarno yang membangkitkan semangat nasionalisme.', 'Bapak Proklamator, penggali Pancasila. Remaja teladan meneladani semangatnya memperjuangkan kemerdekaan'),
(207, 'Mohammad Hatta', 'PENGETAHUAN UMUM', 'Wakil Presiden pertama Indonesia, Proklamator. Contoh: Remaja teladan meneladani kesederhanaan dan kejujuran Bung Hatta.', 'Bapak Koperasi Indonesia. Dikenal sebagai pribadi yang jujur dan sederhana'),
(208, 'ASEAN', 'PENGETAHUAN UMUM', 'Perhimpunan Bangsa-Bangsa Asia Tenggara. Contoh: Remaja teladan mempelajari bahasa Inggris untuk bisa berkomunikasi dengan pemuda ASEAN.', 'Didirikan 8 Agustus 1967 di Bangkok. Anggota: Indonesia, Malaysia, Filipina, Singapura, Thailand, Brunei, Vietnam, Laos, Myanmar, Kamboja'),
(209, 'PBB', 'PENGETAHUAN UMUM', 'Perserikatan Bangsa-Bangsa (UN). Contoh: Remaja teladan mendukung misi perdamaian PBB di berbagai negara.', 'Didirikan 24 Oktober 1945. Indonesia anggota ke-60. Tujuan: menjaga perdamaian dunia'),
(210, 'Global Warming', 'PENGETAHUAN UMUM', 'Pemanasan global akibat efek rumah kaca. Contoh: Remaja teladan mengurangi penggunaan plastik dan menanam pohon untuk mengatasi pemanasan global.', 'Disebabkan emisi CO2, metana, dan gas rumah kaca lainnya. Remaja teladan peduli lingkungan'),
(211, 'COVID-19', 'PENGETAHUAN UMUM', 'Pandemi global yang melanda dunia sejak 2020. Contoh: Remaja teladan mematuhi protokol kesehatan dan membantu sesama yang terpapar.', 'Virus SARS-CoV-2. WHO tetapkan pandemi 11 Maret 2020. Remaja teladan belajar adaptasi di masa krisis'),
(212, 'Narkoba', 'PENGETAHUAN UMUM', 'Narkotika, Psikotropika, dan Bahan Adiktif berbahaya. Contoh: Remaja teladan berani menolak ajakan menggunakan narkoba dan melaporkannya.', 'Dampak: merusak fisik, mental, masa depan, dan dosa di hadapan Tuhan (1 Korintus 6:19-20)'),
(213, 'Bullying', 'PENGETAHUAN UMUM', 'Perundungan, tindakan menyakiti orang lain secara fisik atau verbal. Contoh: Remaja teladan membela korban bullying dan melaporkan ke guru.', 'Dampak: trauma, depresi, bahkan bunuh diri. Remaja teladan anti-perundungan'),
(214, 'Hoaks', 'PENGETAHUAN UMUM', 'Informasi bohong yang disebarkan melalui media. Contoh: Remaja teladan mengecek kebenaran berita sebelum membagikannya.', 'Hoaks memecah belah dan menimbulkan kepanikan. Remaja teladan bijak bermedia sosial'),
(215, 'Korupsi', 'PENGETAHUAN UMUM', 'Penyalahgunaan kepercayaan untuk keuntungan pribadi. Contoh: Remaja teladan jujur dalam ujian dan tidak menyontek sebagai bentuk anti-korupsi.', 'Korupsi adalah kejahatan luar biasa. Remaja teladan membangun integritas sejak dini'),
(216, 'Demokrasi', 'PENGETAHUAN UMUM', 'Sistem pemerintahan dari rakyat, oleh rakyat, untuk rakyat. Contoh: Remaja teladan menggunakan hak pilihnya saat pemilu ketika sudah cukup umur.', 'Indonesia adalah negara demokrasi. Remaja teladan berpartisipasi dalam demokrasi secara bertanggung jawab'),
(217, 'Pemilu', 'PENGETAHUAN UMUM', 'Pemilihan umum untuk memilih wakil rakyat dan presiden. Contoh: Remaja teladan yang sudah 17 tahun menggunakan hak pilihnya dengan bijak.', 'Pemilu 2024 serentak: memilih presiden, DPR, DPD, DPRD. Remaja teladan tidak golput'),
(218, 'Hak Asasi Manusia (HAM)', 'PENGETAHUAN UMUM', 'Hak dasar yang melekat pada setiap manusia. Contoh: Remaja teladan menghormati HAM teman dengan tidak memaksakan kehendak.', 'HAM dilindungi UU. Remaja teladan memahami bahwa HAM dibatasi oleh HAM orang lain'),
(219, 'Kebebasan Beragama', 'PENGETAHUAN UMUM', 'Hak setiap orang memeluk agamanya masing-masing. Contoh: Remaja teladan menghormati teman yang berbeda agama, tidak memaksakan keyakinannya.', 'Pasal 29 UUD 1945. Remaja teladan toleran tanpa mengorbankan iman'),
(220, 'Sumber Daya Alam (SDA)', 'PENGETAHUAN UMUM', 'Kekayaan alam yang dapat dimanfaatkan manusia. Contoh: Remaja teladan menggunakan air dengan hemat sebagai bentuk syukur atas SDA.', 'SDA terbatas. Remaja teladan adalah penjaga alam yang bertanggung jawab'),
(221, 'Teknologi Informasi', 'PENGETAHUAN UMUM', 'Penggunaan teknologi untuk mengolah dan menyebarkan informasi. Contoh: Remaja teladan menggunakan HP untuk belajar Alkitab online, bukan hanya main game.', 'Remaja teladan melek digital tetapi tidak kecanduan. Gunakan teknologi untuk kemuliaan Tuhan'),
(222, 'Media Sosial', 'PENGETAHUAN UMUM', 'Platform digital untuk berinteraksi dan berbagi konten. Contoh: Remaja teladan menggunakan medsos untuk menyebarkan konten rohani yang membangun.', 'Bijak bermedsos: tidak menyebarkan hoaks, ujaran kebencian, atau konten asusila'),
(223, 'Cyberbullying', 'PENGETAHUAN UMUM', 'Perundungan yang dilakukan melalui media digital. Contoh: Remaja teladan tidak ikut-ikutan mengomentari negatif postingan teman.', 'Dampak cyberbullying sangat berbahaya. Remaja teladan menjadi pengguna medsos yang positif'),
(224, 'Investasi', 'PENGETAHUAN UMUM', 'Penanaman modal untuk mendapatkan keuntungan di masa depan. Contoh: Remaja teladan menabung sebagian uang jajan untuk masa depan.', 'Investasi tidak hanya uang, tetapi waktu dan talenta untuk Kerajaan Allah'),
(225, 'Kewirausahaan', 'PENGETAHUAN UMUM', 'Kemampuan menciptakan peluang usaha. Contoh: Remaja teladan membuat kue dan menjualnya untuk menggalang dana kegiatan remaja.', 'Remaja teladan kreatif dan tidak bergantung pada orang tua terus'),
(226, 'Literasi Digital', 'PENGETAHUAN UMUM', 'Kemampuan menggunakan teknologi digital secara bijak. Contoh: Remaja teladan memeriksa kebenaran berita sebelum membagikannya di grup WA.', 'Remaja teladan tidak mudah termakan hoaks. Cek, ricek, baru share'),
(227, 'Olimpiade', 'PENGETAHUAN UMUM', 'Ajang olahraga internasional terbesar. Contoh: Remaja teladan mendukung atlet Indonesia di Olimpiade dengan doa dan dukungan moral.', 'Olimpiade Tokyo 2020 (digelar 2021). Nilai sportivitas dan persahabatan antar bangsa'),
(228, 'Piala Dunia', 'PENGETAHUAN UMUM', 'Kejuaraan sepak bola internasional. Contoh: Remaja teladan menonton Piala Dunia tetapi tidak lupa ibadah.', 'Digelar setiap 4 tahun. Piala Dunia 2022 di Qatar. Remaja teladan tidak fanatik berlebihan'),
(229, 'Revolusi Industri 4.0', 'PENGETAHUAN UMUM', 'Era digital dengan kecerdasan buatan, big data, dan internet of things. Contoh: Remaja teladan mempelajari coding dan AI untuk bersaing di era 4.0.', 'Remaja teladan tidak boleh buta teknologi. Siap menghadapi perubahan zaman'),
(230, 'Vaksin', 'PENGETAHUAN UMUM', 'Zat yang diberikan untuk membentuk kekebalan tubuh terhadap penyakit. Contoh: Remaja teladan mengikuti program vaksinasi untuk melindungi diri dan orang lain.', 'Vaksin adalah berkat ilmu pengetahuan. Remaja teladan tidak termakan hoaks anti-vaksin'),
(231, 'Kesehatan Mental', 'PENGETAHUAN UMUM', 'Kondisi psikologis yang sehat. Contoh: Remaja teladan tidak takut curhat ke orang tua atau pembina saat mengalami tekanan.', 'Mental health penting. Remaja teladan tidak menyembunyikan masalah dan mencari pertolongan'),
(232, 'Pendidikan Karakter', 'PENGETAHUAN UMUM', 'Pembentukan nilai-nilai luhur dalam diri. Contoh: Remaja teladan mengikuti ekstrakurikuler pramuka untuk melatih karakter.', 'Pendidikan karakter membentuk manusia utuh. Remaja teladan tidak hanya cerdas otak tetapi juga hati'),
(233, 'Sumpah Pemuda 1928', 'PENGETAHUAN UMUM', 'Ikrar pemuda Indonesia untuk satu tanah air, satu bangsa, satu bahasa. Contoh: Remaja teladan menggunakan bahasa Indonesia yang baik di lingkungan sekolah.', '28 Oktober 1928. Remaja teladan menghidupkan semangat persatuan'),
(234, 'Hari Pahlawan 10 November', 'PENGETAHUAN UMUM', 'Peringatan pertempuran Surabaya melawan penjajah. Contoh: Remaja teladan mengunjungi makam pahlawan sebagai bentuk penghormatan.', 'Remaja teladan meneladani semangat kepahlawanan dalam konteks kekinian'),
(235, 'Hari Kebangkitan Nasional 20 Mei', 'PENGETAHUAN UMUM', 'Peringatan berdirinya Budi Utomo (1908). Contoh: Remaja teladan membaca buku-buku tentang perjuangan bangsa.', 'Remaja teladan bangkit dari keterpurukan dan berkontribusi bagi bangsa'),
(236, 'Hari Kartini 21 April', 'PENGETAHUAN UMUM', 'Peringatan emansipasi wanita. Contoh: Remaja teladan (laki-laki) membantu pekerjaan rumah tanpa membedakan gender.', 'Remaja teladan mendukung kesetaraan gender yang alkitabiah'),
(237, 'Kepulauan Indonesia', 'PENGETAHUAN UMUM', 'Negara kepulauan terbesar di dunia (17.000+ pulau). Contoh: Remaja teladan bangga menjadi warga negara kepulauan yang kaya akan budaya.', 'Remaja teladan menjaga persatuan meski terpisah lautan'),
(238, 'Ragam Bahasa Daerah', 'PENGETAHUAN UMUM', 'Indonesia memiliki 700+ bahasa daerah. Contoh: Remaja teladan bisa berbahasa daerah sebagai bentuk pelestarian budaya.', 'Bahasa daerah adalah kekayaan bangsa. Remaja teladan tidak malu berbahasa daerah'),
(239, 'Pariwisata Halal', 'PENGETAHUAN UMUM', 'Wisata yang ramah bagi wisatawan muslim. Contoh: Remaja teladan sebagai pemandu wisata menghormati kebutuhan wisatawan muslim.', 'Indonesia adalah destinasi wisata halal dunia. Remaja teladan mendukung pariwisata inklusif'),
(240, 'Ekonomi Kreatif', 'PENGETAHUAN UMUM', 'Ekonomi yang berbasis pada kreativitas dan inovasi. Contoh: Remaja teladan membuat konten YouTube tentang review tempat wisata di Sulut.', 'Remaja teladan tidak hanya jadi konsumen tetapi juga pencipta lapangan kerja'),
(241, 'Startup', 'PENGETAHUAN UMUM', 'Perusahaan rintisan berbasis teknologi. Contoh: Remaja teladan belajar membuat aplikasi sederhana untuk membantu kegiatan gereja.', 'Banyak startup sukses didirikan oleh anak muda. Remaja teladan tidak takut memulai'),
(242, 'Green Economy', 'PENGETAHUAN UMUM', 'Ekonomi yang ramah lingkungan. Contoh: Remaja teladan membawa tas belanja sendiri untuk mengurangi sampah plastik.', 'Remaja teladan peduli pada keberlanjutan bumi'),
(243, 'Koperasi', 'PENGETAHUAN UMUM', 'Badan usaha yang berlandaskan asas kekeluargaan. Contoh: Remaja teladan menabung di koperasi sekolah untuk belajar menabung.', 'Bangun ekonomi kerakyatan. Remaja teladan belajar berkoperasi sejak dini'),
(244, 'UMKM', 'PENGETAHUAN UMUM', 'Usaha Mikro, Kecil, dan Menengah. Contoh: Remaja teladan membeli produk UMKM lokal daripada produk impor.', 'Dukung produk lokal. Remaja teladan bangga pada karya anak bangsa'),
(245, 'Bencana Alam', 'PENGETAHUAN UMUM', 'Peristiwa alam yang merusak dan merugikan. Contoh: Remaja teladan ikut serta dalam aksi penggalangan dana untuk korban bencana.', 'Remaja teladan tanggap bencana: tahu cara evakuasi dan membantu korban'),
(246, 'Mitigasi Bencana', 'PENGETAHUAN UMUM', 'Upaya mengurangi risiko bencana. Contoh: Remaja teladan tidak membuang sampah sembarangan untuk mencegah banjir.', 'Lebih baik mencegah daripada mengobati. Remaja teladan peduli mitigasi'),
(247, 'Toleransi', 'PENGETAHUAN UMUM', 'Sikap saling menghargai antar umat beragama dan kelompok. Contoh: Remaja teladan mengucapkan selamat hari raya kepada teman yang berbeda agama.', 'Indonesia adalah negara toleran. Remaja teladan menjaga kerukunan'),
(248, 'Radikalisme', 'PENGETAHUAN UMUM', 'Paham yang menginginkan perubahan dengan cara kekerasan. Contoh: Remaja teladan menolak ajakan untuk ikut organisasi radikal.', 'Remaja teladan cinta damai dan menolak kekerasan atas nama apapun'),
(249, 'Hoaks Politik', 'PENGETAHUAN UMUM', 'Berita bohong yang bertujuan menjatuhkan lawan politik. Contoh: Remaja teladan tidak ikut menyebarkan berita negatif tentang paslon tanpa bukti.', 'Pemilu damai. Remaja teladan cerdas dan tidak termakan isu SARA'),
(250, 'Bela Negara', 'PENGETAHUAN UMUM', 'Sikap dan perilaku warga negara untuk menjaga kedaulatan negara. Contoh: Remaja teladan mengikuti upacara bendera dengan khidmat dan serius.', 'Bela negara tidak selalu dengan senjata. Belajar sungguh-sungguh juga bela negara'),
(251, 'Remaja Bagi Kristus (Teens for Christ)', 'KEREMAJAAN GMIM', 'Visi pelayanan remaja GMIM bahwa seluruh hidup remaja dipersembahkan bagi Kristus. Contoh: Remaja teladan menggunakan talenta musiknya untuk melayani di gereja, bukan untuk pamer.', 'Visi ini menjadi fondasi semua kegiatan remaja. Remaja teladan menghayati bahwa hidupnya milik Kristus'),
(252, 'Berakar, Bertumbuh, Berbuah', 'KEREMAJAAN GMIM', 'Misi remaja GMIM untuk menjadi remaja yang memiliki dasar iman kuat, terus berkembang, dan membawa dampak. Contoh: Remaja teladan rajin baca Alkitab (berakar), aktif dalam pelayanan (bertumbuh), dan mengajak teman ke gereja (berbuah).', '3B: Berakar (akar iman), Bertumbuh (proses kedewasaan), Berbuah (dampak bagi orang lain)'),
(253, 'LKRG (Latihan Kader Remaja Gereja)', 'KEREMAJAAN GMIM', 'Program pembinaan remaja berjenjang untuk menghasilkan kader gereja yang militan. Contoh: Remaja teladan mengikuti LKRG Dasar, Madya, dan Taruna dengan sungguh-sungguh.', 'LKRG Dasar (pengenalan), Madya (pendalaman), Taruna (pemuridan). Remaja teladan lulus semua jenjang'),
(254, 'Hari Persatuan Remaja GMIM (28 Januari)', 'KEREMAJAAN GMIM', 'Peringatan berdirinya Komisi Pelayanan Remaja Sinode GMIM. Contoh: Remaja teladan memperingati HPRG dengan ibadah syukur dan kegiatan positif.', 'Berdiri 28 Januari 1990 di Palelon Modoinding. Remaja teladan mengenal sejarah pelayanan remajanya'),
(255, 'Pemilihan Remaja Teladan', 'KEREMAJAAN GMIM', 'Ajang seleksi remaja teladan melalui berbagai tahapan yang objektif. Contoh: Remaja teladan mempersiapkan diri dengan belajar dan berlatih wawancara.', 'Tahapan: Tes Tertulis, Wawancara, Karantina, Pelayanan Holistik, Kompetisi Potensi Diri, Final'),
(256, 'KB3 (Komunitas Berakar, Bertumbuh, Berbuah)', 'KEREMAJAAN GMIM', 'Program pemuridan remaja dalam kelompok kecil untuk pertumbuhan iman. Contoh: Remaja teladan mengikuti KB3 di jemaatnya untuk belajar Alkitab bersama.', 'KB3 adalah wadah pembinaan intensif, biasanya terdiri dari 5-10 orang dengan satu pemimpin'),
(257, 'KPRS (Komisi Pelayanan Remaja Sinode)', 'KEREMAJAAN GMIM', 'Organisasi pelayanan remaja di tingkat sinode yang mengoordinasikan seluruh program remaja GMIM. Contoh: Remaja teladan mengenal struktur KPRS dan program-programnya.', 'KPRS memiliki 7-9 bidang, antara lain: P3SDM, APIM, PMB, Litbang, TIK, dll'),
(258, 'KPRW (Komisi Pelayanan Remaja Wilayah)', 'KEREMAJAAN GMIM', 'Organisasi pelayanan remaja di tingkat wilayah. Contoh: Remaja teladan berpartisipasi dalam kegiatan yang diselenggarakan KPRW di wilayahnya.', 'KPRW adalah koordinator program remaja antar jemaat dalam satu wilayah'),
(259, 'KPRJ (Komisi Pelayanan Remaja Jemaat)', 'KEREMAJAAN GMIM', 'Organisasi pelayanan remaja di tingkat jemaat. Contoh: Remaja teladan menjadi pengurus KPRJ sebagai Pembina Remaja.', 'KPRJ diketuai oleh Pembina Remaja (anggota Sidi Jemaat yang sudah LTPR), bukan remaja'),
(260, 'Pembina Remaja', 'KEREMAJAAN GMIM', 'Anggota Sidi Jemaat yang dipilih untuk membina dan mendampingi remaja. Contoh: Remaja teladan menghormati dan mendengarkan nasihat Pembina Remaja.', 'Syarat: Sidi Jemaat, memiliki sertifikat LTPR, dewasa rohani. Remaja teladan merindukan menjadi pembina suatu hari nanti'),
(261, 'LTPR (Latihan Tenaga Pembina Remaja)', 'KEREMAJAAN GMIM', 'Pelatihan untuk menjadi pembina remaja yang berkualitas. Contoh: Remaja teladan yang sudah cukup umur mengikuti LTPR untuk mempersiapkan diri menjadi pembina.', 'LTPR diselenggarakan oleh KPRS. Materi: psikologi remaja, metode pembinaan, kepemimpinan'),
(262, 'PKRS (Perkemahan Kreatif Remaja Sinode)', 'KEREMAJAAN GMIM', 'Perkemahan tahunan remaja GMIM tingkat sinode yang berisi pembinaan, lomba, dan persekutuan. Contoh: Remaja teladan mengikuti PKRS untuk memperluas pergaulan dan belajar hal baru.', 'PKRS biasanya digelar setiap tahun di lokasi yang berbeda-beda di Sulut'),
(263, 'PSR (Pesta Seni Remaja)', 'KEREMAJAAN GMIM', 'Ajang unjuk kreativitas remaja GMIM di bidang seni dan budaya. Contoh: Remaja teladan menampilkan tarian kolintang dalam PSR untuk melestarikan budaya.', 'PSR adalah wadah menyalurkan bakat seni remaja. Remaja teladan mengembangkan kreativitas'),
(264, 'GEMAR (Gerakan Membaca Alkitab Remaja)', 'KEREMAJAAN GMIM', 'Program mendorong remaja membaca Alkitab secara terstruktur. Contoh: Remaja teladan mengikuti tantangan membaca 1 pasal Alkitab setiap hari.', 'GEMAR dikelola Bidang APIM. Remaja teladan menjadi duta GEMAR di jemaatnya'),
(265, 'SIKAT (Sistem Informasi Kegiatan Terpadu)', 'KEREMAJAAN GMIM', 'Platform online pendaftaran kegiatan remaja GMIM. Contoh: Remaja teladan mendaftar mengikuti PKRS melalui SIKAT.', 'SIKAT memudahkan administrasi dan pendataan. Remaja teladan melek teknologi'),
(266, 'Rayon Pelayanan', 'KEREMAJAAN GMIM', 'Pengelompokan wilayah pelayanan KPRS untuk koordinasi (12 Rayon). Contoh: Remaja teladan mengetahui rayonnya dan aktif dalam kegiatan rayon.', 'Rayon: Manado, Bitung, Minut, Minahasa, Minsel, Mitra, Bolmong, Bolsel, Boltim, Kotamobagu, Sangihe, Talaud'),
(267, 'Mars Remaja GMIM', 'KEREMAJAAN GMIM', 'Lagu wajib yang dinyanyikan dalam setiap kegiatan remaja GMIM. Contoh: Remaja teladan hafal dan menyanyikan Mars Remaja GMIM dengan penuh penghayatan.', 'Ciptaan: Pnt. Jantje Wowiling Sajow. Lirik: "Kami remaja GMIM, siap sedia bagi Kristus"'),
(268, 'Lagu "Menjadi Teladan"', 'KEREMAJAAN GMIM', 'Lagu tema Pemilihan Remaja Teladan yang berisi ajakan untuk menjadi teladan. Contoh: Remaja teladan menghayati lirik "jadilah teladan dalam perkataan dan tingkah laku".', 'Ciptaan: Pnt. Ir. Dwight Moody Rondonuwu, MT. Pertama kali dinyanyikan tahun 2015'),
(269, 'Retel (Remaja Teladan)', 'KEREMAJAAN GMIM', 'Singkatan dari Remaja Teladan. Contoh: Remaja teladan bercita-cita menjadi Retel GMIM.', 'Istilah populer dalam Pemilihan Remaja Teladan. Remaja teladan dikenal sebagai Retel'),
(270, 'Karantina', 'KEREMAJAAN GMIM', 'Tahap pembinaan intensif selama 3 hari bagi finalis Remaja Teladan. Contoh: Remaja teladan mempersiapkan fisik dan mental untuk mengikuti karantina.', 'Materi karantina: homiletika, liturgi, multimedia, ketrampilan rumah tangga, adu bakat'),
(271, 'Pelayanan Holistik', 'KEREMAJAAN GMIM', 'Pelayanan yang menyentuh seluruh aspek kehidupan (rohani, jasmani, sosial). Contoh: Remaja teladan mengunjungi panti asuhan sebagai bentuk pelayanan holistik.', 'Ini adalah salah satu tahapan seleksi. Remaja teladan belajar melayani secara utuh'),
(272, 'Kompetisi Potensi Diri', 'KEREMAJAAN GMIM', 'Tahapan lomba yang menguji kemampuan debat, pidato Inggris, dan karya tulis. Contoh: Remaja teladan berlatih debat untuk mempersiapkan kompetisi ini.', 'Tahapan ini terbuka untuk umum. Remaja teladan menunjukkan kualitasnya di depan publik'),
(273, 'Grand Final', 'KEREMAJAAN GMIM', 'Puncak acara Pemilihan Remaja Teladan tingkat sinode. Contoh: Remaja teladan yang masuk Grand Final mempersiapkan diri maksimal untuk tampil terbaik.', 'Di Grand Final, peserta diminta menjelaskan kata kunci yang diambil secara acak'),
(274, 'Gelar Atribut', 'KEREMAJAAN GMIM', 'Gelar khusus selain juara utama, seperti Intelegensia, Persahabatan, Berbakat, Cinta Lingkungan, Favorit. Contoh: Remaja teladan berusaha meraih gelar Remaja Teladan Cinta Lingkungan dengan proyek penghijauan.', 'Setiap gelar memiliki indikator penilaian tersendiri. Remaja teladan berprestasi di berbagai bidang'),
(275, 'Selempang Pelayanan', 'KEREMAJAAN GMIM', 'Selempang yang dikenakan finalis Remaja Teladan berwarna ungu. Contoh: Remaja teladan bangga mengenakan selempang ungu sebagai finalis.', 'Selempang sinode: dasar hitam tulisan emas; rayon: hitam perak; wilayah: ungu emas; jemaat: ungu perak'),
(276, 'Tahapan Seleksi', 'KEREMAJAAN GMIM', 'Rangkaian proses seleksi Remaja Teladan: Tes Tertulis → Wawancara → Karantina → Pelayanan Holistik → Kompetisi Potensi Diri → Final/Grand Final. Contoh: Remaja teladan mempersiapkan diri di setiap tahapan dengan serius.', 'Setiap tahapan memiliki bobot penilaian: Tes Tertulis 5%, Wawancara 15%, Karantina+Holistik 35%, Kompetisi 25%, Final 20%'),
(277, 'Kata Kunci Final', 'KEREMAJAAN GMIM', '3 kata kunci yang diambil acak peserta final untuk dijelaskan di depan juri. Contoh: Remaja teladan berlatih menjelaskan hubungan antara "Integritas, Pelayanan, Keteladanan".', 'Kata kunci ditulis juri di kertas, dimasukkan wadah, peserta mengambil secara acak. Uji spontanitas'),
(278, '3 Besar', 'KEREMAJAAN GMIM', 'Babak penentuan juara di mana nilai sebelumnya tidak dipakai. Contoh: Remaja teladan tampil maksimal di babak 3 besar karena ini penentu kemenangan.', 'Di babak ini, semua peserta mendapat pertanyaan yang sama. Yang terbaiklah yang menang'),
(279, 'Etika Remaja Teladan', 'KEREMAJAAN GMIM', 'Pedoman perilaku yang harus dipatuhi Remaja Teladan GMIM. Contoh: Remaja teladan tidak merokok, berpakaian sopan, dan menjaga pergaulan.', 'Etika diatur dalam Pedoman Etika Remaja Teladan GMIM. Pelanggaran mendapat sanksi'),
(280, 'Toga dan Stola', 'KEREMAJAAN GMIM', 'Pakaian jabatan Pelayan Khusus GMIM. Contoh: Remaja teladan mengetahui makna toga putih (persekutuan dengan kematian dan kebangkitan Kristus).', 'Toga hitam (duka cita?), putih (kebangkitan), ungu (pertobatan). Stola sesuai tahun gerejawi'),
(281, 'Tahun Pelayanan', 'KEREMAJAAN GMIM', 'Periode pelayanan GMIM di setiap aras. Contoh: Remaja teladan mengetahui bahwa periode pelayanan BPMS adalah 5 tahun (1 April - 31 Maret).', 'Aras jemaat: 1 Januari - 31 Desember; Wilayah: 1 Maret - 28/29 Februari; Sinode: 1 April - 31 Maret'),
(282, 'Sidang Majelis', 'KEREMAJAAN GMIM', 'Forum pengambilan keputusan tertinggi di setiap aras (Jemaat, Wilayah, Sinode). Contoh: Remaja teladan menghormati keputusan Sidang Majelis Jemaat di gerejanya.', 'Keputusan Sidang Majelis Sinode adalah tertinggi. Remaja teladan tunduk pada keputusan sidang'),
(283, 'Kemitraan', 'KEREMAJAAN GMIM', 'Kerjasama antar jemaat, wilayah, atau dengan gereja lain. Contoh: Remaja teladan mengikuti pertukaran pemuda dengan gereja mitra.', 'Kemitraan memperkuat pelayanan. Remaja teladan membangun jaringan persaudaraan'),
(284, 'Misi Pengutusan', 'KEREMAJAAN GMIM', 'Pengiriman tenaga pelayanan ke daerah atau gereja yang membutuhkan. Contoh: Remaja teladan mendukung misi pengutusan dengan doa dan dana.', 'Ini adalah pola strategi pelayanan remaja: Penginjilan → Pembinaan → Pelipatgandaan → Pengutusan'),
(285, 'Pelipatgandaan', 'KEREMAJAAN GMIM', 'Proses melatih orang lain untuk melakukan apa yang kita lakukan. Contoh: Remaja teladan yang bisa main gitar mengajar temannya sehingga bisa bergantian melayani.', 'Inilah pola Yesus: memuridkan 12 murid, lalu mereka memuridkan yang lain. Remaja teladan tidak bekerja sendiri'),
(286, 'Model Remaja Lukas 2:52', 'KEREMAJAAN GMIM', 'Remaja yang bertumbuh dalam 4 aspek: fisik, hikmat (intelektual), rohani, dan sosial. Contoh: Remaja teladan menjaga kesehatan (fisik), rajin belajar (intelektual), tekun berdoa (rohani), dan bersahabat dengan semua (sosial).', 'Inilah model remaja ideal GMIM. Remaja teladan berusaha seimbang dalam semua aspek'),
(287, 'Aspek Fisik', 'KEREMAJAAN GMIM', 'Menjaga kesehatan tubuh sebagai bait Roh Kudus. Contoh: Remaja teladan berolahraga teratur dan tidak merokok.', '1 Korintus 6:19. Tubuh adalah bait Roh Kudus. Remaja teladan tidak merusak tubuh dengan narkoba, alkohol, atau gaya hidup tidak sehat'),
(288, 'Aspek Intelektual', 'KEREMAJAAN GMIM', 'Bertumbuh dalam pengetahuan dan hikmat. Contoh: Remaja teladan rajin membaca buku dan belajar dengan sungguh-sungguh.', 'Amsal 4:7 - "Perolehlah hikmat". Remaja teladan tidak malas belajar, karena pengetahuan adalah anugerah Tuhan'),
(289, 'Aspek Spiritual', 'KEREMAJAAN GMIM', 'Bertumbuh dalam hubungan dengan Tuhan. Contoh: Remaja teladan memiliki waktu teduh setiap hari dan aktif dalam ibadah.', 'Ini adalah aspek yang paling penting. Remaja teladan tidak mengabaikan kehidupan rohaninya'),
(290, 'Aspek Sosial', 'KEREMAJAAN GMIM', 'Bertumbuh dalam hubungan dengan sesama. Contoh: Remaja teladan ramah pada semua orang, tidak pilih-pilih teman.', 'Yesus juga bertumbuh dalam kasih Allah dan manusia. Remaja teladan membangun relasi yang sehat'),
(291, 'Pelayanan Diakonia', 'KEREMAJAAN GMIM', 'Pelayanan kasih kepada yang membutuhkan. Contoh: Remaja teladan mengumpulkan pakaian layak pakai untuk korban bencana.', 'Diakonia adalah salah satu panggilan gereja. Remaja teladan memiliki kepedulian sosial tinggi'),
(292, 'Pelayanan Marturia', 'KEREMAJAAN GMIM', 'Pelayanan kesaksian tentang Kristus. Contoh: Remaja teladan bersaksi dengan mengajak teman ke gereja.', 'Setiap remaja adalah saksi Kristus. Remaja teladan tidak malu mengaku Kristen'),
(293, 'Pelayanan Koinonia', 'KEREMAJAAN GMIM', 'Pelayanan persekutuan antar sesama percaya. Contoh: Remaja teladan hadir dalam setiap ibadah dan kegiatan persekutuan.', 'Koinonia menguatkan iman. Remaja teladan tidak menyendiri tetapi membangun kebersamaan'),
(294, 'Pelayanan Leiturgia', 'KEREMAJAAN GMIM', 'Pelayanan ibadah dan penyembahan. Contoh: Remaja teladan melayani sebagai liturgos, pemusik, atau paduan suara.', 'Ibadah adalah respon manusia kepada Tuhan. Remaja teladan melayani dengan hati yang sungguh-sungguh'),
(295, 'Pendalaman Alkitab (PA)', 'KEREMAJAAN GMIM', 'Kegiatan mempelajari Alkitab secara mendalam dalam kelompok kecil. Contoh: Remaja teladan aktif mengikuti PA remaja setiap minggu.', 'PA adalah sarana bertumbuh dalam pengenalan akan Firman Tuhan. Remaja teladan tidak malas ber-PA'),
(296, 'Ibadah Remaja', 'KEREMAJAAN GMIM', 'Ibadah khusus untuk remaja yang dikemas secara kreatif dan relevan. Contoh: Remaja teladan hadir dalam ibadah remaja dan membawa teman.', 'Ibadah remaja adalah wadah pembinaan iman yang sesuai dengan dunia remaja'),
(297, 'Kreativitas Remaja', 'KEREMAJAAN GMIM', 'Kemampuan menciptakan sesuatu yang baru dan bermanfaat dalam pelayanan. Contoh: Remaja teladan membuat video animasi Alkitab untuk ditayangkan di ibadah remaja.', 'Kreativitas membuat pelayanan tidak membosankan. Remaja teladan inovatif'),
(298, 'Kader Milenial', 'KEREMAJAAN GMIM', 'Generasi remaja yang dipersiapkan menjadi pemimpin masa depan. Contoh: Remaja teladan mengikuti LKRG dan pelatihan kepemimpinan untuk menjadi kader milenial.', 'Gereja butuh pemimpin milenial yang berkarakter Kristus. Remaja teladan menjawab panggilan ini'),
(299, 'Spiritualitas Remaja', 'KEREMAJAAN GMIM', 'Kedalaman hubungan pribadi remaja dengan Tuhan. Contoh: Remaja teladan memiliki kerinduan untuk berdoa dan membaca firman, bukan karena dipaksa.', 'Spiritualitas bukan tentang ritual, tetapi relasi. Remaja teladan jatuh cinta pada Tuhan'),
(300, 'Komitmen Remaja', 'KEREMAJAAN GMIM', 'Keteguhan hati untuk tetap setia kepada Tuhan dan pelayanan. Contoh: Remaja teladan tetap datang ke gereja meski hujan atau banyak tugas sekolah.', 'Komitmen diuji dalam kesulitan. Remaja teladan tidak mudah goyah'),
(301, 'Bunaken', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Taman Laut Nasional di Sulawesi Utara, spot diving kelas dunia. Contoh: Remaja teladan mengajak wisatawan asing untuk snorkeling di Bunaken sambil menjelaskan keindahan ciptaan Tuhan.', 'Terumbu karang Bunaken adalah yang terkaya di dunia. Remaja teladan bangga dan ikut menjaga kelestariannya'),
(302, 'Tinutuan (Bubur Manado)', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Makanan khas Sulawesi Utara berupa bubur dengan sayuran dan jagung. Contoh: Remaja teladan memperkenalkan Tinutuan kepada teman dari luar daerah sebagai kuliner sehat.', 'Tinutuan adalah makanan bergizi dan menjadi ikon kuliner Manado. Remaja teladan bisa memasaknya'),
(303, 'Danau Tondano', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Danau terluas di Sulawesi Utara, terletak di Kabupaten Minahasa. Contoh: Remaja teladan mengajak keluarga piknik di Danau Tondano sambil menikmati pemandangan alam.', 'Danau Tondano adalah sumber kehidupan bagi masyarakat sekitar. Remaja teladan ikut menjaga kebersihannya'),
(304, 'Gunung Lokon', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Gunung berapi aktif di Tomohon yang terkenal dengan "Gunung Api Tomohon". Contoh: Remaja teladan mendaki Gunung Lokon sebagai bentuk apresiasi pada keindahan ciptaan Tuhan.', 'Pemandangan dari puncak Lokon sangat indah. Remaja teladan tetap waspada karena statusnya gunung aktif'),
(305, 'Gunung Mahawu', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Gunung di Tomohon dengan kawah yang indah dan pemandangan Danau Tondano. Contoh: Remaja teladan mengajak teman-teman mendaki Gunung Mahawu untuk refreshing.', 'Pendakian ke Mahawu relatif mudah, cocok untuk pemula. Remaja teladan menjaga kebersihan selama pendakian'),
(306, 'Bukit Kasih Kanonang', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Tempat wisata religi di Minahasa dengan simbol kerukunan antar umat beragama. Contoh: Remaja teladan mengunjungi Bukit Kasih untuk belajar tentang toleransi.', 'Terdapat 5 rumah ibadah berbeda dalam satu kawasan. Remaja teladan menghormati simbol kerukunan ini'),
(307, 'Tari Maengket', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Tarian tradisional Minahasa yang menggambarkan sukacita panen. Contoh: Remaja teladan menarikan Maengket dalam acara kebudayaan di sekolah.', 'Maengket memiliki 3 babak: Maowey Kamberu, Marambak, Lalayaan. Remaja teladan melestarikan tarian daerah'),
(308, 'Kolintang', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Alat musik pukul kayu khas Minahasa yang diakui UNESCO. Contoh: Remaja teladan belajar memainkan kolintang untuk mengisi ibadah.', 'Kolintang masuk Warisan Budaya Tak Benda UNESCO 2019. Remaja teladan bangga dengan warisan budaya ini'),
(309, 'Wale', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Rumah adat Minahasa berbentuk panggung dengan atap tinggi. Contoh: Remaja teladan menjelaskan arsitektur Wale kepada wisatawan yang berkunjung.', 'Wale memiliki makna filosofis: dekat dengan leluhur (tinggi) dan jauh dari binatang buas (panggung)'),
(310, 'Mapalus', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Budaya gotong royong masyarakat Minahasa. Contoh: Remaja teladan mengamalkan Mapalus dengan membantu membersihkan lingkungan gereja bersama-sama.', 'Nilai Mapalus selaras dengan ajaran Alkitab tentang kebersamaan. Remaja teladan menghidupinya'),
(311, 'Sitou Timou Tumou Tou', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Falsafah Minahasa: "Manusia hidup untuk memanusiakan manusia lain". Contoh: Remaja teladan menjadi relawan untuk mengajar anak-anak putus sekolah.', 'Falsafah ini menjadi semboyan pelayanan GMIM. Remaja teladan mewujudkannya dalam aksi nyata'),
(312, 'Bahasa Tombulu', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Salah satu bahasa daerah di Minahasa yang digunakan di wilayah Tomohon dan sekitarnya. Contoh: Remaja teladan menyapa teman dengan "Magi" (selamat pagi) dalam bahasa Tombulu.', 'Remaja teladan melestarikan bahasa daerah sebagai identitas budaya'),
(313, 'Bahasa Tondano', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Bahasa daerah yang digunakan di wilayah Tondano dan sekitarnya. Contoh: Remaja teladan belajar bahasa Tondano untuk berkomunikasi dengan kakek-neneknya.', 'Bahasa daerah terancam punah. Remaja teladan berperan melestarikannya'),
(314, 'Bahasa Tonsawang', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Bahasa daerah di wilayah Tombatu, Minahasa Tenggara. Contoh: Remaja teladan dari Tombatu bangga bisa berbahasa Tonsawang.', 'Setiap bahasa daerah adalah kekayaan bangsa. Remaja teladan tidak malu menggunakannya'),
(315, 'Bahasa Bolaang Mongondow', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Bahasa daerah di Kabupaten Bolaang Mongondow Raya. Contoh: Remaja teladan dari Bolmong menggunakan bahasa daerahnya saat berbicara dengan teman sebaya.', 'Remaja teladan menjaga identitas budayanya di tengah arus globalisasi'),
(316, 'Bahasa Sangihe', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Bahasa daerah di Kepulauan Sangihe dan Talaud. Contoh: Remaja teladan dari Sangihe melestarikan bahasanya dengan ikut lomba pidato bahasa daerah.', 'Bahasa Sangihe memiliki dialek yang berbeda-beda di setiap pulau. Remaja teladan mempelajarinya'),
(317, 'What is your hobby? (English)', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', '"My hobby is reading the Bible and singing worship songs." Contoh: Remaja teladan menjawab pertanyaan wawancara Bahasa Inggris dengan percaya diri.', 'Latihan menjawab pertanyaan umum dalam Bahasa Inggris. Remaja teladan tidak gugup'),
(318, 'Why do you want to be an exemplary youth?', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', '"I want to be a role model for my friends and glorify God through my life." Contoh: Remaja teladan menjelaskan motivasinya dalam Bahasa Inggris dengan lancar.', 'Ini adalah pertanyaan umum dalam wawancara. Remaja teladan mempersiapkan jawabannya'),
(319, 'Can you introduce yourself in English?', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', '"My name is... I am 15 years old. I come from... My hobby is... My dream is to be..." Contoh: Remaja teladan berlatih perkenalan diri dalam Bahasa Inggris setiap hari.', 'Perkenalan diri adalah pertanyaan pertama yang biasanya muncul. Remaja teladan siap'),
(320, 'What is your favorite Bible verse?', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', '"My favorite verse is 1 Timothy 4:12 - Don''t let anyone look down on you because you are young." Contoh: Remaja teladan hafal ayat Alkitab favorit dalam Bahasa Inggris.', 'Hafalkan ayat kunci dalam Bahasa Inggris. Remaja teladan siap menjawab pertanyaan rohani'),
(321, 'How do you say "Saya bangga menjadi orang Minahasa" in English?', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', '"I am proud to be a Minahasan." Contoh: Remaja teladan mengungkapkan kebanggaannya terhadap budaya Minahasa dalam Bahasa Inggris.', 'Kebanggaan pada identitas budaya harus bisa diungkapkan dalam bahasa internasional'),
(322, 'What is "Tinutuan" in English?', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', '"Tinutuan is Manado porridge, made of vegetables, corn, and pumpkin." Contoh: Remaja teladan menjelaskan makanan khas kepada turis asing dalam Bahasa Inggris.', 'Remaja teladan menjadi duta kuliner Sulut. Belajar menjelaskan makanan daerah dalam Bahasa Inggris'),
(323, 'Where is Bunaken located?', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', '"Bunaken is located in Manado, North Sulawesi, Indonesia." Contoh: Remaja teladan menunjukkan lokasi Bunaken di peta dunia dalam Bahasa Inggris.', 'Remaja teladan hafal lokasi wisata unggulan Sulut dalam Bahasa Inggris'),
(324, 'What can tourists do in Bunaken?', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', '"Tourists can go snorkeling, diving, and enjoy the beautiful coral reefs and fish." Contoh: Remaja teladan merekomendasikan aktivitas wisata di Bunaken dalam Bahasa Inggris.', 'Remaja teladan mempromosikan pariwisata Sulut secara aktif'),
(325, 'Festival Likupang', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Festival wisata bahari di Likupang, Minahasa Utara, yang menarik wisatawan mancanegara. Contoh: Remaja teladan menjadi relawan dalam Festival Likupang untuk membantu wisatawan asing.', 'Likupang ditetapkan sebagai Destinasi Wisata Super Prioritas. Remaja teladan mendukungnya'),
(326, 'Sail Tomini', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Event wisata bahari yang digelar di Teluk Tomini. Contoh: Remaja teladan ikut serta dalam acara Sail Tomini sebagai panitia muda.', 'Event ini mempromosikan pariwisata Sulawesi. Remaja teladan bangga terlibat'),
(327, 'Waruga', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Peti kubur batu khas Minahasa berbentuk kubus. Contoh: Remaja teladan mengunjungi situs Waruga di Sawangan untuk belajar sejarah.', 'Waruga adalah warisan megalitikum. Remaja teladan menghormati peninggalan leluhur'),
(328, 'Watu Pinawetengan', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Situs batu megalitikum di Minahasa yang menjadi tempat pembagian wilayah oleh nenek moyang. Contoh: Remaja teladan belajar sejarah Minahasa di Watu Pinawetengan.', 'Menurut legenda, ini tempat Toar dan Lumimuut membagi wilayah. Remaja teladan mengenal asal-usulnya'),
(329, 'Parang dan Salawaku', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Senjata tradisional Minahasa (parang untuk menyerang, salawaku untuk perisai). Contoh: Remaja teladan mempelajari tarian perang yang menggunakan parang dan salawaku.', 'Senjata ini digunakan dalam tarian perang Kabasaran. Remaja teladan melestarikan budaya'),
(330, 'Kabasaran', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Tarian perang Minahasa yang menggunakan parang dan salawaku. Contoh: Remaja teladan menonton pertunjukan Kabasaran untuk mengenal budaya perang Minahasa.', 'Kabasaran kini lebih sebagai atraksi budaya. Remaja teladan menghargai warisan leluhur'),
(331, 'Pa''Benteng', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Tradisi adu ketangkasan dengan saling pukul menggunakan rotan dengan perisai. Contoh: Remaja teladan mengikuti Pa''Benteng sebagai olahraga tradisional.', 'Pa''Benteng menguji ketangkasan dan keberanian. Remaja teladan menjaga sportivitas'),
(332, 'Tumatenden', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Alat musik tradisional Minahasa seperti gong. Contoh: Remaja teladan belajar memainkan tumatenden untuk mengiringi tarian Maengket.', 'Tumatenden adalah pengiring penting dalam musik tradisional Minahasa'),
(333, 'Popondi', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Alat musik tiup tradisional Minahasa. Contoh: Remaja teladan mencoba meniup popondi untuk belajar alat musik tradisional.', 'Popondi mirip suling tetapi dengan suara khas. Remaja teladan melestarikan warisan musik'),
(334, 'Sasando', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Alat musik petik dari Nusa Tenggara Timur (meski bukan Sulut, tapi tetap budaya Indonesia). Contoh: Remaja teladan mengetahui alat musik tradisional dari daerah lain sebagai wawasan nusantara.', 'Remaja teladan memiliki wawasan budaya nasional, tidak hanya daerah sendiri'),
(335, 'Angklung', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Alat musik bambu dari Jawa Barat, diakui UNESCO. Contoh: Remaja teladan bisa memainkan angklung sebagai bentuk apresiasi budaya nasional.', 'Remaja teladan tidak hanya bangga dengan budaya Minahasa tetapi juga budaya Indonesia secara umum'),
(336, '"Thank you" in various local languages (Tombulu)', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', '"Magkamo" atau "Makase" (Tombulu). Contoh: Remaja teladan mengucapkan terima kasih dalam bahasa daerah kepada orang tua.', 'Remaja teladan tahu cara berterima kasih dalam berbagai bahasa daerah di Sulut'),
(337, '"How are you?" in English response', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', '"I am fine, thank you. How about you?" Contoh: Remaja teladan menjawab sapaan dalam Bahasa Inggris dengan sopan.', 'Ini adalah dasar percakapan Bahasa Inggris. Remaja teladan menguasainya'),
(338, '"Excuse me, where is the nearest church?"', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', '"Go straight, then turn left. The church is on your right." Contoh: Remaja teladan membantu turis asing menemukan gereja dalam Bahasa Inggris.', 'Remaja teladan menjadi pemandu wisata rohani bagi wisatawan asing'),
(339, '"What is the traditional clothing of Minahasa?"', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', '"The traditional clothing is called ''Pakaian Adat Minahasa'' with ''Lapik'' and ''Kamben''." Contoh: Remaja teladan mengenakan pakaian adat Minahasa dalam acara kebudayaan.', 'Remaja teladan bangga mengenakan pakaian adat dan bisa menjelaskannya dalam Bahasa Inggris'),
(340, 'Lapik', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Kain tenun tradisional Minahasa yang digunakan sebagai bawahan. Contoh: Remaja teladan mengenakan Lapik dalam acara pernikahan adat.', 'Lapik memiliki motif khas Minahasa. Remaja teladan melestarikan wastra tradisional'),
(341, 'Kamben', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Kain penutup badan bagian atas dalam pakaian adat Minahasa. Contoh: Remaja teladan memakai Kamben saat menjadi pemandu acara adat.', 'Remaja teladan tahu cara mengenakan Kamben dengan benar'),
(342, 'Tonaas', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Pemimpin adat atau pemuka agama tradisional Minahasa. Contoh: Remaja teladan menghormati Tonaas sebagai tokoh budaya.', 'Sebelum Kristen masuk, Tonaas memimpin upacara adat. Remaja teladan menghargai sejarah'),
(343, 'Walewangko', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Mahkota atau hiasan kepala dalam pakaian adat Minahasa. Contoh: Remaja teladan memakai Walewangko saat menjadi pengantin adat.', 'Walewangko melambangkan keagungan. Remaja teladan memakainya dengan hormat'),
(344, 'Maleosan', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Upacara adat kelahiran dalam masyarakat Minahasa. Contoh: Remaja teladan mengetahui makna Maleosan sebagai ucapan syukur atas kelahiran.', 'Remaja teladan menghargai setiap siklus kehidupan dalam budaya Minahasa'),
(345, 'Rumamba', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Upacara adat kematian dalam masyarakat Minahasa. Contoh: Remaja teladan ikut serta dalam upacara Rumamba sebagai bentuk penghormatan pada yang meninggal.', 'Remaja teladan menghormati adat istiadat tanpa meninggalkan iman Kristen'),
(346, 'Fosso', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Upacara adat penguburan di Minahasa. Contoh: Remaja teladan membantu persiapan Fosso untuk anggota jemaat yang meninggal.', 'Fosso adalah bagian dari prosesi adat yang sudah diinkulturasi dengan kekristenan'),
(347, 'Tourism Awareness', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Kesadaran untuk menjaga dan mempromosikan pariwisata daerah. Contoh: Remaja teladan tidak membuang sampah di tempat wisata dan mengajak teman-temannya untuk melakukan hal yang sama.', 'Remaja teladan adalah duta wisata yang baik. Mereka menjaga kebersihan dan keramahan'),
(348, 'Creative Economy', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Ekonomi yang berbasis pada kreativitas, termasuk kerajinan tangan dan kuliner. Contoh: Remaja teladan membuat gantungan kunci dari kayu kolintang mini untuk dijual kepada wisatawan.', 'Remaja teladan menciptakan peluang ekonomi dari potensi budaya lokal'),
(349, 'Cultural Heritage', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Warisan budaya yang perlu dilestarikan. Contoh: Remaja teladan mengajak teman-temannya untuk belajar menari Maengket agar tidak punah.', 'Remaja teladan adalah generasi penerus yang menjaga warisan budaya'),
(350, 'Global Citizen with Local Identity', 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Warga global yang tetap mempertahankan identitas lokal. Contoh: Remaja teladan fasih berbahasa Inggris (global) tetapi tetap bangga menggunakan bahasa Tombulu (lokal).', 'Remaja teladan tidak kehilangan jati diri di tengah arus globalisasi. Mereka bisa bersaing secara global tetapi tetap berakar pada budaya lokal');
